  ('eisencarbonat', 'Eisencarbonat', 'Eisencarbonat, Eisen(II)-carbonat, Siderit, Kohlensaures Eisen, E505', 'Ferrous Carbonate, Iron Carbonate, Iron(II) Carbonate, Siderite, FeCO3', 'eisencarbonat, ferrous carbonate, iron carbonate, siderit, E505', 'Kohlensaures Eisen', 'Calciumcarbonat (CaCO₃), Magnesiumcarbonat (MgCO₃)', 'Eisencarbonat = FeCO₃, Mineral "Siderit". E505 als Lebensmittelzusatzstoff. OBSOLET für NEM wegen extrem schlechter Löslichkeit/Absorption!'),
  ('ammoniumeisencitrat', 'Ammoniumeisen(III)-citrat', 'Ammoniumeisencitrat, Eisenammoniumcitrat, Ammoniumeisen(III)-citrat, Ferric Ammonium Citrate, E381', 'Ferric Ammonium Citrate, Ammonium Iron(III) Citrate, Iron Ammonium Citrate, FAC', 'ammoniumeisencitrat, ferric ammonium citrate, E381, eisenammoniumcitrat', 'Grünes Eisenammoniumcitrat, Braunes Eisenammoniumcitrat, Eisen-Ammonium-Citrat', 'Eisen(II)-citrat (Fe²⁺!), Eisen(III)-citrat (ohne Ammonium), Natriumeisencitrat', 'Ammoniumeisen(III)-citrat = Fe³⁺ + Ammonium + Citrat. E381 als Lebensmittelzusatzstoff. NICHT verwechseln mit Eisen(II)-citrat (andere CAS-Nr, andere Eigenschaften).'),
  ('carbonyleisen', 'Carbonyleisen', 'Carbonyleisen, Carbonyl-Eisen, Elementares Eisen, Hochreines Eisen', 'Carbonyl Iron, Elemental Iron (Carbonyl), CI, Pure Iron', 'carbonyleisen, carbonyl iron, elemental iron, hochreines eisen', 'Reineisen, Metallisches Eisen', 'Eisensulfat (Salz!), Eisenfumarat (Salz!), Reduziertes Eisen, Elektrolytisches Eisen', 'Carbonyleisen = reines elementares Fe⁰ (~98%), hergestellt aus Fe(CO)₅. NICHT verwechseln mit Eisensalzen! Unterscheidet sich von reduziertem/elektrolytischem Eisen durch sphärische Partikelform.'),
