  ('kaliumgluconat', 'Kaliumgluconat', 'Kaliumgluconat, K-Gluconat, Kaliumgluconat-Monohydrat, E577', 'Potassium Gluconate, Potassium D-gluconate, E577', 'kaliumgluconat, k-gluconat, potassium gluconate, e577', 'Kalium-Tabletten (OTC), Kalium-Kapseln', 'Kaliumchlorid (höherer K-Gehalt), Kaliumcitrat (alkalisierend)', 'K-Gluconat enthält nur 16,69% Kalium (niedrigster Gehalt!). Beste GI-Verträglichkeit. E577 = LM-Zusatzstoff-Nummer. Für 99 mg K braucht man ~593 mg K-Gluconat!'),
  ('kaliumaspartat', 'Kaliumaspartat', 'Kaliumaspartat, Kalium-L-aspartat, Kalium-DL-aspartat, K-Aspartat', 'Potassium Aspartate, Potassium L-aspartate, K-Aspartate', 'kaliumaspartat, k-aspartat, potassium aspartate', 'Panangin (Osteuropa), Asparkam (Russland) - als Arzneimittel!', '❌ NICHT mit zugelassenen K-Formen verwechseln! Tromcardin® enthält Mg-Aspartat + KCl (NICHT K-Aspartat!)', '❌ NICHT ZUGELASSEN in EU für NEM! Trotz EFSA Opinion 883 (2008). In USA zugelassen. In Osteuropa als Arzneimittel (K-Mg-Aspartat).'),
  ('kaliumbicarbonat', 'Kaliumbicarbonat', 'Kaliumbicarbonat, KHCO3, Kaliumhydrogencarbonat, K-Bicarbonat, E501(ii)', 'Potassium Bicarbonate, Potassium hydrogen carbonate, KHCO3, E501(ii)', 'kaliumbicarbonat, k-bicarbonat, khco3, e501ii, e501(ii)', 'Brausetabletten-Kalium, Brause-Kalium', 'Kaliumcarbonat (E501i) - anderes Salz!; Natriumbicarbonat (Natron) - anderes Kation!', 'KHCO3 ≠ K2CO3 (Kaliumcarbonat)! Bicarbonat = Hydrogencarbonat = HCO3-. E501(ii) = Bicarbonat, E501(i) = Carbonat.'),
  ('kaliumdihydrogenphosphat', 'Kaliumdihydrogenphosphat', 'KH2PO4, Monopotassium phosphate, MKP, E340(i), primäres Kaliumphosphat, Kaliumphosphat monobasisch', 'Potassium Dihydrogen Phosphate, Monobasic Potassium Phosphate, MKP, E340(i)', 'kh2po4, mkp, e340i, e340(i), kaliumphosphat', 'Kaliumphosphat (allgemein)', 'K2HPO4 (dibasisch), K3PO4 (tribasisch) - andere Formen! Natriumphosphat - anderes Kation!', 'SAUER (pH ~4,5)! E340(i) = monobasisch. ⚠️ Enthält Phosphat → EFSA ADI beachten!'),
  ('dikaliumhydrogenphosphat', 'Dikaliumhydrogenphosphat', 'K2HPO4, Dipotassium phosphate, DKP, E340(ii), sekundäres Kaliumphosphat, Kaliumphosphat dibasisch', 'Dipotassium Hydrogen Phosphate, Dibasic Potassium Phosphate, DKP, E340(ii)', 'k2hpo4, dkp, e340ii, e340(ii), dikaliumphosphat', 'Kaliumphosphat (allgemein)', 'KH2PO4 (monobasisch), K3PO4 (tribasisch) - andere Formen!', 'BASISCH (pH 8,7-9,4)! E340(ii) = dibasisch. HÖCHSTER K-Gehalt der Phosphate (44,89%). IV-Infusionen!'),
  ('trikaliumphosphat', 'Trikaliumphosphat', 'K3PO4, Tripotassium phosphate, E340(iii), tertiäres Kaliumphosphat', 'Tripotassium Phosphate, Tribasic Potassium Phosphate, E340(iii)', 'k3po4, e340iii, e340(iii), trikaliumphosphat', '-', 'KH2PO4, K2HPO4 - andere Formen!', '⚠️ STARK BASISCH (pH ~11,8) = potentiell ätzend! E340(iii). Für NEM NICHT EMPFOHLEN!'),
