  ('natriumchlorid', 'Natriumchlorid', 'Natriumchlorid, NaCl, Kochsalz, Speisesalz, Tafelsalz', 'Sodium Chloride, Table Salt, Common Salt, NaCl', 'nacl, kochsalz, speisesalz, salz, natriumchlorid', 'Salz, Meersalz, Himalayasalz, Steinsalz', 'Natriumbicarbonat (Natron) - anderes Salz!; Natriumascorbat - Vitamin-C-Salz!', 'Alle Speisesalze (Meersalz, Himalayasalz, etc.) sind chemisch NaCl mit Spurenelementen. "Gesündere" Salze sind Marketing - der Na-Gehalt ist identisch!'),
  ('natriumbicarbonat', 'Natriumbicarbonat', 'Natron, NaHCO3, Natriumhydrogencarbonat, Speisenatron, Backsoda, E500(ii), Bullrich-Salz, Kaiser Natron', 'Sodium Bicarbonate, Baking Soda, NaHCO3, Bicarbonate of Soda, E500(ii)', 'natriumbicarbonat, natron, nahco3, e500ii, e500(ii), bakingsoda, baking soda', 'Natron, Backnatron, Bullrich', 'Natriumcarbonat (E500i, Soda) - ANDERES Salz! Kaliumbicarbonat - anderes Kation!', 'NaHCO3 (Bicarbonat) ≠ Na2CO3 (Carbonat)! Bicarbonat = Hydrogencarbonat. E500(ii) = Bicarbonat, E500(i) = Carbonat.'),
  ('natriumdihydrogenphosphat', 'Natriumdihydrogenphosphat', 'NaH2PO4, Monosodium Phosphate, MSP, E339(i), Primäres Natriumphosphat, Monobasisches Natriumphosphat', 'Sodium Dihydrogen Phosphate, Monobasic Sodium Phosphate, MSP, E339(i)', 'nah2po4, msp, e339i, e339(i), natriumphosphat', 'Natriumphosphat', 'Na2HPO4 (dibasisch), Na3PO4 (tribasisch) - ANDERE Formen! Kaliumphosphate - anderes Kation!', 'SAUER (pH ~4,5)! E339(i) = monobasisch. ⚠️ Enthält Phosphat → EFSA ADI beachten!'),
  ('dinatriumhydrogenphosphat', 'Dinatriumhydrogenphosphat', 'Na2HPO4, Disodium Phosphate, DSP, E339(ii), Sekundäres Natriumphosphat, Dibasisches Natriumphosphat', 'Disodium Hydrogen Phosphate, Dibasic Sodium Phosphate, DSP, E339(ii)', 'na2hpo4, dsp, e339ii, e339(ii), dinatriumphosphat', 'Natriumphosphat', 'NaH2PO4 (mono), Na3PO4 (tri) - ANDERE Formen!', 'BASISCH (pH 8,7-9,4)! E339(ii) = dibasisch. Höherer Na-Gehalt (32,39%).'),
