  ('lactobacillus-delbrueckii-bulgaricus', 'Lactobacillus delbrueckii subsp. bulgaricus', 'L. bulgaricus, Joghurtbakterium, Bulgaricus, Milchsäurebakterium', 'L. bulgaricus, Lactobacillus bulgaricus, yogurt bacteria', 'Laktobazillus bulgarikus, Lactobacilus bulgaricus', 'Joghurt-Kultur, Jogurt-Bakterie', 'L. acidophilus (anderer Stamm), L. lactis (andere Subspezies)', '⭐ Genusname NICHT geändert 2020 (Typspezies). Entdeckt 1905 von Stamen Grigorov in Bulgarien. Typstamm ATCC 11842. Obligat homofermentativ. EINZIGER EU-Health Claim!'),
  ('lactobacillus-delbrueckii-bulgaricus-lb40', 'LBA-40™', 'LBA-40, Chr. Hansen LBA-40', 'LBA-40, Chr. Hansen', '-', '-', '-', 'Chr. Hansen Stamm für Joghurtproduktion.'),
  ('lactobacillus-delbrueckii-bulgaricus-glb44', 'GLB44', 'GLB44, Bulgarischer Stamm', 'GLB44', '-', '-', '-', 'Bulgarischer Stamm. ⚠️ Opekun 2018: 0% H. pylori-Eradikation als Monotherapie!'),
  ('limosilactobacillus-fermentum', 'Limosilactobacillus fermentum', 'L. fermentum, Lactobacillus fermentum (alt)', 'L. fermentum, Lactobacillus fermentum, Limosilactobacillus fermentum', 'Laktobazillus fermentum', '-', 'L. reuteri RC-14 (NICHT L. fermentum!)', '⭐ 2020 umbenannt zu Limosilactobacillus (Zheng et al.). Typstamm ATCC 14931. Obligat HETEROFERMENTATIV (produziert CO₂!).'),
  ('limosilactobacillus-fermentum-cect5716', '⭐ L. fermentum CECT5716 (LC40)', 'CECT5716, LC40, Hereditum LC40, Hereditum Breastcare', 'CECT5716, LC40, Hereditum', '-', 'Muttermilch-Probiotikum, Stillprobiotikum', 'ME-3 (andere Indikation!)', '⭐ ERSTER AUS MUTTERMILCH ISOLIERTER KOMMERZIELLER STAMM! Biosearch Life / Kerry Group. Hereditum®. Zugelassen in China für Säuglingsnahrung (2016). Partnerschaften: Nestlé, HiPP.'),
  ('limosilactobacillus-fermentum-me3', '⭐ L. fermentum ME-3 (DSM 14241)', 'ME-3, DSM 14241, Reg''Activ, Terviseks', 'ME-3, DSM 14241, Reg''Activ', '-', 'Glutathion-Probiotikum, Antioxidans-Probiotikum', 'CECT5716 (andere Indikation!)', '⭐ EINZIGARTIGES PROBIOTIKUM MIT KOMPLETTEM GLUTATHION-SYSTEM! Entdeckt 1995, Universität Tartu (Estland), Prof. Marika Mikelsaar. Reg''Activ® (VF Bioscience, Essential Formulas).'),
  ('wichtiger-hinweis-rc14', '⚠️ RC-14 ist NICHT L. fermentum!', 'RC-14', 'RC-14', '-', '-', '-', '⚠️ WICHTIGE KORREKTUR! RC-14 wurde umklassifiziert zu Limosilactobacillus REUTERI RC-14. Wird mit L. rhamnosus GR-1 kombiniert (UREX-Formel). NICHT L. fermentum!'),
  ('natriumacetat', 'Natriumacetat', 'Natriumacetat, E262, E262i, Essigsäure-Natriumsalz, Sodium Acetate', 'Sodium Acetate, E262, Acetic Acid Sodium Salt', 'Natriumazetat, Natrium-Acetat', 'Essig-Salz', '⚠️ NICHT VERWECHSELN: Natriumacetat ≠ Natriumbutyrat (andere SCFA!)', '⭐ Häufigste SCFA (~60%). E262 zugelassen. Systemisch wirksam.'),
  ('calciumacetat', 'Calciumacetat', 'Calciumacetat, E263, Calcium Acetate, PhosLo, Calciumacetat-Nefro', 'Calcium Acetate, E263, PhosLo', 'Kalziumacetat', 'Phosphatbinder', '⭐ Natriumfrei! Doppelfunktion: Acetat + Calcium + Phosphatbinder.', '⭐ E263. Arzneimittel für Dialyse.'),
  ('apfelessig', 'Apfelessig', 'Apfelessig, Apple Cider Vinegar, ACV, Essig, Essigsäure', 'Apple Cider Vinegar, ACV, Vinegar', 'Apfel-Essig, Apfelweinessig', 'Essig, Hausmittel', '⚠️ Nicht mit reinem Essig verwechseln (Essigsäure kann bis 25% sein!)', '⭐ 5% Essigsäure. Populärste Acetat-Quelle. Verdünnen!'),
  ('kefiran', 'Kefiran', 'Kefiran, Kefir-Polysaccharid, Glucogalactan', 'Kefiran, Kefir Polysaccharide', 'Kefirian', 'Kefir-Schleim', '⚠️ Kefiran ≠ Kefir! Kefiran ist das EPS aus Kefir-Körnern.', '⭐ Postbiotikum. Glucogalactan. MW 534-760 kDa.'),
  ('xanthan', 'Xanthan (E415)', 'Xanthan, Xanthan Gum, E415, Xanthangummi', 'Xanthan Gum, E415', 'Xanthan-Gum', 'Verdickungsmittel', 'Lebensmittelzusatzstoff, kein Supplement.', '⭐ E415. EFSA-zugelassen.'),
  ('gellan', 'Gellan (E418)', 'Gellan, Gellan Gum, E418, Gellangummi', 'Gellan Gum, E418', 'Gellan-Gum', 'Geliermittel', 'Lebensmittelzusatzstoff, kein Supplement.', '⭐ E418. EFSA-zugelassen.'),
  ('dextran', 'Dextran', 'Dextran, α-1,6-Glucan, Leuconostoc-Polysaccharid', 'Dextran, Alpha-1,6-Glucan', 'Dextrane', 'Blutplasma-Expander', '⚠️ Medizinprodukt! Nicht als NEM.', 'α-1,6-Glucan aus Leuconostoc.'),
  ('arabinogalactan', 'Arabinogalactan (Lärche)', 'Lärchenholz-Arabinogalactan, AG, LAG, Galactoarabinan, Lärchen-Polysaccharid', 'larch arabinogalactan, arabinogalactan, AG, LAG, galactoarabinan', 'Arabinogalaktan, Arabinogalactane', 'Lärchenfaser, Immunfaser', '⚠️ NICHT VERWECHSELN: Arabinogalactan (Lärche) ≠ Arabinose (Zucker) ≠ Galactan (Pektin)', 'AG aus Lärche = Polysaccharid. Arabinose = Monosaccharid. Verschiedene Substanzen!'),
  ('phgg', 'PHGG (Teilweise hydrolysiertes Guarkernmehl)', 'Sunfiber, OptiFibre, Guarkernmehl hydrolysiert, Galactomannan, teilhydrolysiertes Guar', 'PHGG, partially hydrolyzed guar gum, Sunfiber, OptiFibre, galactomannan', 'PHGG, P.H.G.G., Guargummi', 'Guarkernmehl (aber hydrolysiert!), Guarbohnenfaser', '⚠️⚠️ NICHT VERWECHSELN: PHGG ≠ Natives Guarkernmehl (E412)! PHGG hat NIEDRIGE Viskosität. Natives Guar ist hochviskos.', '✅ PHGG = enzymatisch hydrolysiert, MW ~20kDa, niedrige Viskosität. Natives Guar = hochviskos, MW 200-300kDa. ⚠️ Benefiber® USA enthält KEIN PHGG mehr (seit 2006 Weizendextrin)!'),
  ('lactobacillus-gasseri', 'Lactobacillus gasseri', 'L. gasseri, Gasseri', 'L. gasseri, Lactobacillus gasseri', 'Laktobazillus gasseri', '-', 'L. acidophilus, L. johnsonii (verwandt)', '⭐ Genusname 2020 BEIBEHALTEN (Zheng et al.). Typstamm ATCC 33323. Obligat homofermentativ. 14 Mucin-bindende Proteine (höchste Anzahl!). Natürlich in Vagina, Muttermilch, GI-Trakt.'),
  ('lactobacillus-gasseri-sbt2055', '⭐ L. gasseri SBT2055', 'SBT2055, Snow Brand SBT2055, Megmilk SBT2055', 'SBT2055, Snow Brand', '-', 'Gewichts-Probiotikum, Bauchfett-Probiotikum', 'BNR17 (anderer Gewichts-Stamm)', '⭐ JAPAN FOSHU 2018 für viszerales Fett! Megmilk Snow Brand (Japan). Mechanismus: Fett-Emulsions-Vergrößerung → ↓Fettabsorption. 12 Wochen für Effekt.'),
  ('lactobacillus-gasseri-bnr17', 'L. gasseri BNR17', 'BNR17, Bioneer BNR17', 'BNR17, Bioneer', '-', 'Gewichts-Probiotikum', 'SBT2055 (etablierter)', 'Bioneer Corporation (Korea). Isoliert aus Muttermilch. FDA GRAS Notice 1089. Korea-Zulassung für Körperfett. ✅ Keine biogenen Amine (bestätigt).'),
  ('lactobacillus-gasseri-cp2305', '⭐ L. gasseri CP2305 (Paraprobiotic)', 'CP2305, Asahi CP2305, Cocalm', 'CP2305, Asahi', '-', 'Stress-Probiotikum, Schlaf-Probiotikum, Postbiotic', '-', '⭐ HITZE-INAKTIVIERTES PARAPROBIOTIC! Asahi Group (Japan). Seit 2025 exklusiv ADM für Europa/USA. Wirkt über Darm-Hirn-Achse auch ohne lebende Zellen.'),
  ('lactobacillus-gasseri-oll2809', 'L. gasseri OLL2809', 'OLL2809, Meiji OLL2809', 'OLL2809, Meiji', '-', 'Allergie-Probiotikum', '-', 'Meiji (Japan). Starker IL-12-Stimulator. Anwendung: Zedernpollenallergie, Endometriose-Schmerzen. 100 mg hitze-inaktiviert/Tag.'),
  ('lactobacillus-helveticus', 'Lactobacillus helveticus', 'L. helveticus, Helveticus', 'L. helveticus, Lactobacillus helveticus', 'Laktobazillus helvetikus', 'Käsebakterium, Schweizer-Käse-Bakterium', 'L. delbrueckii (verwandt)', '⭐ Genusname 2020 BEIBEHALTEN. Typstamm ATCC 15009. Obligat homofermentativ, THERMOPHIL (42-52°C). HÖCHSTE proteolytische Aktivität! Klassischer Käsestarter (Emmentaler, Gruyère, Parmesan).'),
  ('lactobacillus-helveticus-cm4', '⭐ L. helveticus CM4 (Calpis/AmealPeptide)', 'CM4, Calpis, AmealPeptide, Ameel', 'CM4, Calpis, AmealPeptide', '-', 'Blutdruck-Probiotikum, ACE-Hemmer natürlich', '-', '⭐ JAPAN FOSHU 1997 für Blutdruck (70% des Marktes)! Calpis/Asahi (Japan). Produziert IPP/VPP Peptide (ACE-Hemmung). Fermentation mit S. cerevisiae.'),
  ('ipp-vpp-peptide', '⭐ IPP/VPP (Lactotripeptide)', 'IPP, VPP, Ile-Pro-Pro, Val-Pro-Pro, Lactotripeptide', 'IPP, VPP, lactotripeptides', '-', 'Blutdruck-Peptide, natürliche ACE-Hemmer', 'Captopril (1000x potenter)', '⭐ ACE-inhibitorische Tripeptide aus Casein. IPP: IC50 5 μM. VPP: IC50 9 μM. ~0,1% Bioverfügbarkeit (picomolar). Resistent gegen GI-Verdauung.'),
  ('lactium', '⭐ Lactium® (α-Casozepine)', 'Lactium, Casozepine, αS1-Casein Tryptic Hydrolysate', 'Lactium, Casozepine', '-', 'Stress-Peptid, Anti-Angst natürlich, natürliches Beruhigungsmittel', 'Benzodiazepine (synthetisch)', '⭐ KEIN PROBIOTIKUM! Casein-Hydrolysat von Ingredia (Frankreich). Aktives Peptid: α-Casozepine (YLGYLEQLLR). Bindet GABAA-Rezeptor. Wirkt NUR unter Stress, keine Abhängigkeit!'),
  ('lactobacillus-helveticus-l10', 'L. helveticus Lafti L10', 'Lafti L10, L10, Lallemand L10', 'Lafti L10, Lallemand', '-', 'Sportler-Probiotikum, Immun-Probiotikum', '-', 'Lallemand (Kanada). Fokus: Immunsystem für Leistungssportler. Health Canada-Claims für Sportler (antioxidativ, Immununterstützung). RCT: URTI-Dauer -3,4 Tage.'),
  ('lactobacillus-helveticus-r0052', 'L. helveticus R0052 (Rosell-52)', 'R0052, Rosell-52, CNCM I-1722, Lacidofil', 'R0052, Rosell-52', '-', '-', '-', 'Lallemand (Kanada). Ursprünglich als L. acidophilus klassifiziert. FDA GRAS für Säuglingsnahrung. Lacidofil® = R0052 + L. rhamnosus R0011. Kombination mit B. longum R0175 für Stress.'),
  ('om-85', 'OM-85 (Broncho-Vaxom®)', 'Broncho-Vaxom, Broncho-Munal, Ommunal, Vaxoral, OM-85 BV, Bakterienlysat', 'OM-85, Broncho-Vaxom, Bacterial Lysate, Immunostimulant', 'Broncho Vaxom, Bronchovaxom, OM85', 'Immunstimulans, Abwehrkräfte-Stärkung', '⚠️ ARZNEIMITTEL! Nicht mit Probiotika oder NEM verwechseln.', '⭐ Probiotika (lebende Bakterien), NEM. OM-85 = ARZNEIMITTEL mit Zulassung.'),
  ('ismigen', 'Ismigen® (PMBL)', 'Ismigen, Respibron, Pulmigen, PMBL', 'Ismigen, PMBL, Polyvalent Mechanical Bacterial Lysate', 'Ismigen', 'Sublingualtablette', '⚠️ ARZNEIMITTEL! Unterschied zu OM-85: MECHANISCHE Lyse.', '⭐ OM-85 (chemische Lyse). Ismigen = mechanisch → höhere Immunogenität.'),
  ('uro-vaxom', 'Uro-Vaxom® (OM-89)', 'Uro-Vaxom, OM-89, E. coli-Lysat', 'Uro-Vaxom, OM-89, E. coli Lysate', 'Urovaxom', 'Blasenimmunisierung', '⚠️ Spezifisch für UTI! Nicht mit OM-85 verwechseln.', '⭐ OM-85 = Atemwege. Uro-Vaxom = Harnwege (E. coli-Stämme).'),
  ('nisin', 'Nisin (E234)', 'Nisin, E234, Nisaplin, Lantibiotikum', 'Nisin, E234, Nisaplin, Lantibiotic', 'Nisin', 'Konservierungsmittel', '⚠️ LEBENSMITTELZUSATZSTOFF! Kein Supplement.', '⭐ Antibiotika (chemisch synthetisiert). Nisin = natürliches Bakteriocin.'),
  ('pediocin-pa1', 'Pediocin PA-1', 'Pediocin PA-1, ALTA 2341', 'Pediocin PA-1, ALTA 2341, Class IIa Bacteriocin', 'Pediocin', '-', '⚠️ KEINE EU-Zulassung! Nur Forschung.', '⭐ Nisin (E234) = zugelassen. Pediocin = NICHT zugelassen.'),
  ('reuterin', 'Reuterin', 'Reuterin, 3-HPA, 3-Hydroxypropionaldehyd', 'Reuterin, 3-HPA, 3-Hydroxypropionaldehyde', 'Reuterin', 'L. reuteri-Substanz', '⚠️ Kein klassisches Bakteriocin! Metabolit von L. reuteri.', '⭐ Bakteriocine (Peptide). Reuterin = Aldehyd-Metabolit.'),
  ('lacticin-3147', 'Lacticin 3147', 'Lacticin 3147, LtnA1/LtnA2', 'Lacticin 3147, Two-component lantibiotic', 'Lacticin', '-', '⚠️ Nur Forschung! Keine Zulassung.', '⭐ Nisin (zugelassen). Lacticin = Forschungssubstanz.'),
