  ('lacticaseibacillus-paracasei-lpc37', 'L. paracasei Lpc-37', 'Lpc-37, Lpc37, HOWARU Calm', 'Lpc-37, HOWARU Calm', '-', 'Stress-Probiotikum', '-', 'IFF (ehemals Danisco/DuPont). SISU-Studie für Stress/Angst. 17,5 Mrd. KBE/Tag.'),
  ('lacticaseibacillus-paracasei-f19', 'L. paracasei F19', 'F19, LMG P-17806', 'F19', '-', 'Baby-Probiotikum, Allergie-Probiotikum', '-', 'Arla (Schweden). Für Säuglingsbeikost. Ekzem-Prävention (NNT=9). West-Studien.'),
  ('lacticaseibacillus-paracasei-dg', 'L. paracasei DG', 'DG, CNCM I-1572, Enterolactis', 'DG, Enterolactis', '-', 'Reizdarm-Probiotikum', '-', 'Sofar (Italien). Enterolactis®. IBS, symptomatische Divertikelkrankheit. 2×24 Mrd. KBE/Tag.'),
  ('lacticaseibacillus-paracasei-431', 'L. paracasei L. CASEI 431', 'L. CASEI 431, CNCM I-1518, Chr. Hansen 431', 'L. CASEI 431', '-', 'Immun-Probiotikum', '-', 'Chr. Hansen/Novonesis. Verbesserte Impfantwort. Sicher bis 50 Mrd. KBE/Tag.'),
  ('limosilactobacillus-reuteri', 'Limosilactobacillus reuteri', 'L. reuteri, Lmb. reuteri, Lactobacillus reuteri (alt)', 'L. reuteri, Limosilactobacillus reuteri', 'Laktobazillus reuteri, Lactobacillus rojteri', '-', '-', '⭐ 2020 UMBENANNT zu LIMOSILACTOBACILLUS (Zheng et al. PMID: 32293557). Typstamm ATCC 23272. Obligat heterofermentativ. Produziert REUTERIN (antimikrobiell).'),
  ('limosilactobacillus-reuteri-dsm17938', '⭐⭐⭐ L. reuteri DSM17938 (Protectis)', 'DSM17938, DSM 17938, Protectis, BioGaia Protectis', 'DSM17938, Protectis, BioGaia', 'DSM17398', 'Baby-Tropfen, Koliken-Tropfen, Schreibaby-Tropfen', 'ATCC PTA 6475 (anderer Stamm)', '⭐⭐⭐ GOLDSTANDARD FÜR SÄUGLINGSKOLIKEN! BioGaia (Schweden). NNT 2,6 bei gestillten Säuglingen. ESPGHAN Level 1. Ab Geburt geeignet. 5 Tropfen = 10⁸ KBE.'),
  ('limosilactobacillus-reuteri-6475', 'L. reuteri ATCC PTA 6475 (Osfortis)', 'ATCC PTA 6475, 6475, Osfortis', 'ATCC PTA 6475, Osfortis', '-', 'Knochen-Probiotikum', 'DSM17938 (anderer Stamm)', 'BioGaia. Für Knochengesundheit. Kombination mit Vitamin D3. Positive Ergebnisse nur bei älteren Frauen (75-80 J.).'),
  ('limosilactobacillus-reuteri-prodentis', '⭐ L. reuteri Prodentis', 'Prodentis, BioGaia Prodentis, DSM17938+ATCC PTA 5289', 'Prodentis, BioGaia Prodentis', '-', 'Zahnfleisch-Probiotikum, Mundgesundheit-Probiotikum', '-', '⭐ BioGaia. KOMBINATION: DSM17938 + ATCC PTA 5289 für Mundgesundheit. Lutschtabletten. Evidenz für Gingivitis, Parodontitis, Karies.'),
  ('limosilactobacillus-reuteri-rc14', 'L. reuteri RC-14', 'RC-14, RC14, UREX', 'RC-14, UREX', '-', 'Vaginal-Probiotikum, Frauen-Probiotikum', '-', '⚠️ TAXONOMISCHE GESCHICHTE: 1985 L. acidophilus → 1998 L. fermentum → später L. reuteri → 2020 Limosilactobacillus reuteri RC-14. Novonesis. UREX® = RC-14 + L. rhamnosus GR-1. Vaginalgesundheit. Produziert KEIN Reuterin (PCR-bestätigt).'),
  ('guarkernmehl-nativ', 'Guarkernmehl (nativ, E412)', 'Guarkernmehl, Guar, E412, Guaran, Guarbohnenmehl, Guargummi', 'guar gum, guar, E412, guaran, guar flour, guar bean gum, cyamopsis gum', 'Guarkermehl, Guarkernmeh, Guar-Kernmehl', 'Guar', '⚠️⚠️ KRITISCH: Guarkernmehl (nativ, E412) ≠ PHGG (teilhydrolysiert)! Natives Guar = HOCHVISKOS, OBSTRUKTIONSRISIKO! PHGG = SICHER, LOW-FODMAP!', 'Natives Guarkernmehl: MW 200.000-8.000.000 Da, Viskosität 6.000-7.500 mPa·s. PHGG: MW ~20.000 Da, Viskosität ~10 mPa·s. VÖLLIG UNTERSCHIEDLICHE SICHERHEITSPROFILE!'),
  ('synbiotika', 'Synbiotika', 'Synbiotikum, Symbiotika, Prä+Probiotika', 'Synbiotics, Synbiotic, Symbiotics', 'Synbiotika, Symbiotika, Synbioticum', 'Darmflora-Kombi, Bakterien+Ballaststoffe', '⚠️ Unterschied Probiotika/Präbiotika beachten!', '⭐ Probiotika = nur lebende Bakterien. Präbiotika = nur Substrat. Synbiotika = BEIDES!'),
  ('ashwagandha', 'Ashwagandha', 'Schlafbeere, Winterkirsche, Withania somnifera, Indischer Ginseng', 'Ashwagandha, Indian Ginseng, Winter Cherry, Withania', 'Ashwaganda, Aswagandha, Ashwaganda (Schreibfehler häufig)', 'Schlafbeere, Stressbeere', '⚠️ Kein echter Ginseng! Andere Pflanzenfamilie.', '⭐ Panax Ginseng = Araliaceae. Ashwagandha = Solanaceae (Nachtschatten). Unterschiedliche Wirkmechanismen.'),
  ('ashwagandha-ksm66', 'KSM-66', 'KSM-66, Ixoreal Ashwagandha', 'KSM-66, Ixoreal Ashwagandha Extract', 'KSM66, KSM 66', '-', '⚠️ Unterschied zu Sensoril und Shoden beachten!', '⭐ KSM-66 = NUR Wurzel, 5% Withanolide. Sensoril = Wurzel+Blatt, 10%. Shoden = 35%.'),
  ('ashwagandha-sensoril', 'Sensoril', 'Sensoril, Natreon Ashwagandha', 'Sensoril, Natreon Ashwagandha Extract', 'Sensoril', '-', '⚠️ Enthält auch BLATT (höherer Withaferin-A-Gehalt).', '⭐ Sensoril = Wurzel+Blatt. Besser für Schlaf. Abends einnehmen.'),
  ('ashwagandha-shoden', 'Shoden', 'Shoden, Arjuna Natural Ashwagandha', 'Shoden, Arjuna Natural Extract', 'Shoden', '-', '⚠️ HÖCHSTE Konzentration! Niedrigste Dosis nötig.', '⭐ Shoden = 35% Withanolide. Nur 60-120 mg/Tag nötig vs. 300-600 mg bei KSM-66.'),
  ('polydextrose', 'Polydextrose (E1200)', 'Polydextrose, PDX, E1200, Litesse, Sta-Lite', 'polydextrose, PDX, E1200, Litesse, Sta-Lite', 'Polidextrose, Poly-dextrose', 'PDX', '⚠️ Polydextrose ≠ Maltodextrin! Maltodextrin ist NICHT kalorienarm und hat hohen GI!', 'Polydextrose: ~1 kcal/g, GI 4-7. Maltodextrin: ~4 kcal/g, GI 85-105!'),
  ('lactulose', 'Lactulose', 'Lactulose, Duphalac, Bifiteral, Lactuverlan, Laevolac', 'lactulose, Duphalac, Enulose, Generlac, Kristalose', 'Laktulose, Lactu-lose', 'Duphalac, Laevolac', '⚠️ Lactulose ≠ Lactose! Lactulose ist NICHT verdaulich und wird als Laxativum/Präbiotikum verwendet!', 'Lactulose: Galactose + FRUCTOSE (β-1,4). Lactose: Galactose + GLUCOSE (β-1,4). Völlig unterschiedliche Wirkung!'),
  ('ligilactobacillus-salivarius', 'Ligilactobacillus salivarius', 'L. salivarius, Lg. salivarius, Lactobacillus salivarius (alt)', 'L. salivarius, Ligilactobacillus salivarius', 'Laktobazillus salivarius, Lactobacillus salivarius', 'Speichel-Laktobazillus', 'L. salivarius (nah verwandt mit L. agilis, L. ruminis)', '⭐ 2020 UMBENANNT von Lactobacillus zu LIGILACTOBACILLUS (Zheng et al. PMID: 32293557). Typstamm ATCC 11741. Obligat homofermentativ (L-Laktat). Produziert ABP-118 Bakteriozin.'),
  ('ligilactobacillus-salivarius-cect5713', '⭐⭐ L. salivarius CECT 5713 / PS2 (Mastitis)', 'CECT 5713, CECT5713, PS2, Mastitis-Probiotikum', 'CECT 5713, PS2, mastitis probiotic', '-', 'Stillprobiotikum, Brust-Probiotikum', '-', '⭐⭐ UNIVERSIDAD COMPLUTENSE MADRID. Erster Stamm aus Muttermilch UND Säuglingsfäzes gleichzeitig isoliert! BESTE EVIDENZ für MASTITIS. 10⁹ KBE/Tag. Prävention: 25% vs. 57%!'),
  ('ligilactobacillus-salivarius-ucc118', 'L. salivarius UCC118', 'UCC118, UCC 118', 'UCC118', '-', '-', '-', 'UNIVERSITY COLLEGE CORK (Irland). Erster vollständig sequenzierter L. salivarius. Produziert ABP-118 (Breitspektrum-Bakteriozin gegen Listeria, Bacillus, Enterococcus). Darmgesundheit, Permeabilität.'),
  ('ligilactobacillus-salivarius-wb21', '⭐ L. salivarius WB21 (Mundgesundheit)', 'WB21, WB 21', 'WB21', '-', 'Mund-Probiotikum, Zahnfleisch-Probiotikum', '-', '⭐ WAKAMOTO PHARMACEUTICAL (Japan). Für Mundgesundheit entwickelt. Lutschtabletten. Evidenz für Parodontitis, Gingivitis, Halitosis. 6,7×10⁸-2×10⁹ KBE/Tag.'),
  ('ligilactobacillus-salivarius-ls01', 'L. salivarius LS01 (DSM 22775)', 'LS01, LS-01, DSM 22775', 'LS01, DSM 22775', '-', '-', '-', 'PROBIOTICAL SpA (Italien). Atopische Dermatitis. Moduliert Th1/Th2-Zytokin-Verhältnis.'),
  ('ligilactobacillus-salivarius-ls33', 'L. salivarius Ls-33', 'Ls-33, Ls33, LS33', 'Ls-33', '-', '-', '-', 'PROBI AB / CHR. HANSEN (Schweden). Darmbarriere. Erhöht Bacteroides/Firmicutes-Ratio.'),
  ('lactobacillus-johnsonii', 'Lactobacillus johnsonii', 'L. johnsonii, Lb. johnsonii', 'L. johnsonii, Lactobacillus johnsonii', 'Laktobazillus johnsonii', '-', 'L. acidophilus (verwandt, Teil des Acidophilus-Komplexes)', '⭐ 2020: BLEIBT bei LACTOBACILLUS (nicht umbenannt!). Typstamm ATCC 33200. Obligat homofermentativ (D-Laktat). Teil des Acidophilus-Komplexes. Benannt nach John L. Johnson.'),
  ('lactobacillus-johnsonii-la1', '⭐ L. johnsonii LA1 / NCC533 / LC1 (Nestlé)', 'LA1, La1, La-1, NCC533, NCC 533, LC1, CNCM I-1225', 'LA1, La1, NCC533, LC1', 'La-1, L. acidophilus La1 (FALSCH!)', 'Nestlé-Probiotikum, LC1-Joghurt', '⚠️ NICHT L. acidophilus! Frühere Fehlbezeichnung.', '⭐ NESTLÉ (Schweiz). Wichtigster kommerzieller Stamm. LC1-Joghurt. ⚠️ LA1, La1, La-1 = DERSELBE Stamm NCC533! H. pylori-Suppression (keine Eradikation). 10⁹ KBE/90g Joghurt.'),
  ('lactobacillus-johnsonii-n62', 'L. johnsonii N6.2 (T1D-Forschung)', 'N6.2, N6-2, N62', 'N6.2', '-', 'Diabetes-Probiotikum', '-', 'UNIVERSITY OF FLORIDA. Typ-1-Diabetes-Forschung. Aus BB-DR-Ratten isoliert. Moduliert Tryptophan-Stoffwechsel, TLR9-Aktivierung. Laufende Studien (NCT03961347).'),
  ('lactobacillus-johnsonii-1088', 'L. johnsonii No. 1088', 'No. 1088, 1088, No1088', 'No. 1088, 1088', '-', '-', '-', 'SNOWDEN CO. (Japan). Aus Magensaft isoliert. EXTREME SÄURERESISTENZ (>10% Überlebensrate bei pH 1,0)! Stärkste Anti-H. pylori-Aktivität. NUR präklinische Daten!'),
  ('lactobacillus-johnsonii-mh68', '⭐ L. johnsonii MH-68 (Allergie)', 'MH-68, MH68', 'MH-68', '-', 'Allergie-Probiotikum', '-', '⭐ TAIWAN. Allergische Rhinitis bei Kindern. + Levocetirizin: IFN-γ↑, IL-10↑, IL-4↓. Effekt persistiert 3 Monate!'),
  ('lactacin-f', 'Lactacin F (Bakteriozin)', 'Lactacin F, LafA, LafX', 'Lactacin F', '-', '-', '-', 'BAKTERIOZIN von L. johnsonii VPI 11088. Class II Zwei-Peptid-System. Hemmt Enterococcus faecalis und andere Laktobazillen.'),
  ('abp-118', 'ABP-118 (Bakteriozin von L. salivarius)', 'ABP-118, ABP118, Abp118', 'ABP-118', '-', '-', '-', '⭐ BREITSPEKTRUM-BAKTERIOZIN von L. salivarius UCC118. Class IIb Zwei-Peptid. Hemmt Listeria monocytogenes, Bacillus, Enterococcus, Staphylococcus.'),
  ('lactitol', 'Lactitol (E966)', 'Lactitol, Lactit, E966, Importal', 'lactitol, E966, Importal, Pizensy', 'Laktitol, Lacti-tol', 'Importal', '⚠️ Lactitol ≠ Lactulose! Lactitol = Polyol (Zuckeralkohol). Lactulose = Disaccharid.', 'Lactitol: Galactose + SORBITOL. Lactulose: Galactose + FRUCTOSE. Beide bei HE wirksam.'),
  ('flohsamenschalen', 'Flohsamenschalen (Psyllium)', 'Flohsamenschalen, Psyllium, Flohsamen, Plantago ovata, Indische Flohsamen, Ispaghula', 'psyllium husk, psyllium, Plantago ovata, ispaghula, blonde psyllium, Metamucil', 'Flohsamen-Schalen, Psylliumschalen, Psillium', 'Metamucil, Mucofalk', '⚠️ Flohsamenschalen ≠ ganze Flohsamen! Schalen haben 5x höheres Quellvermögen und sind wirksamer!', 'Schalen (Testa-Epidermis): ≥40-fach Quellung. Ganze Samen: nur 8-9-fach. IMMER Schalen bevorzugen!'),
  ('lactobacillus-crispatus', 'Lactobacillus crispatus', 'L. crispatus, Lb. crispatus', 'L. crispatus, Lactobacillus crispatus', 'Laktobazillus crispatus', 'Vaginal-Lactobacillus, Scheidenflora-Bakterium', 'L. acidophilus (verwandt, aber andere Art)', '⭐ 2020: BLEIBT bei LACTOBACILLUS (nicht umbenannt!). Typstamm ATCC 33820. ⭐⭐ WICHTIGSTER VAGINALER LACTOBACILLUS! Definiert CST I (Community State Type I) = gesunde Vaginalflora.'),
  ('lactobacillus-crispatus-ctv05', '⭐⭐ L. crispatus CTV-05 (LACTIN-V)', 'CTV-05, CTV05, LACTIN-V, LACTINV', 'CTV-05, LACTIN-V', '-', 'BV-Probiotikum, Vaginalprobiotikum', '-', '⭐⭐ OSEL INC. (USA). Am besten erforschter L. crispatus-Stamm! Phase 2b NEJM (Cohen 2020). BV-Rezidiv 30% vs. 45%. 2×10⁹ KBE vaginal.'),
  ('lactobacillus-crispatus-ip174178', '⭐ L. crispatus IP 174178 (Physioflor)', 'IP 174178, IP174178, Physioflor', 'IP 174178, Physioflor', '-', 'Vaginal-Probiotikum', '-', '⭐ FRANKREICH. Produziert 5 mM H₂O₂. Phase III: 79,5% vs. 59% Rezidivfreiheit bei BV (Bohbot 2018).'),
  ('lactobacillus-crispatus-lbv88', 'L. crispatus LBV88 (DSM 22566)', 'LBV88, LBV 88, DSM 22566', 'LBV88, DSM 22566', '-', '-', '-', 'Teil von Jarro-Dophilus Women. Meta-Analyse: Signifikante Nugent-Score-Reduktion (de Vrese 2019).'),
  ('lactobacillus-crispatus-m247', '⭐ L. crispatus M247 (Crispact)', 'M247, Crispact', 'M247, Crispact', '-', 'Orales Vaginalprobiotikum', '-', '⭐ ITALIEN. ORAL appliziert (20 Mrd. KBE), zeigt vaginale Kolonisation! Produziert mehrere Bakteriozine.'),
  ('cst-i', 'CST I (Community State Type I)', 'CST I, CST-I, CST1, Community State Type I', 'CST I, Community State Type I', '-', 'Gesunde Vaginalflora, optimale Scheidenflora', 'CST IV (BV-assoziiert)', '⭐ L. crispatus-dominierte Vaginalflora bei 10-40% prämenopausaler Frauen. Als OPTIMAL angesehen. Niedriges BV/STI-Risiko.'),
  ('lactobacillus-delbrueckii', 'Lactobacillus delbrueckii', 'L. delbrueckii, Lb. delbrueckii', 'L. delbrueckii, Lactobacillus delbrueckii', 'Laktobazillus delbrueckii', '-', '-', '⭐ 2020: BLEIBT bei LACTOBACILLUS - ist sogar TYPSPEZIES des neu definierten Genus! Typstamm ATCC 9649. Benannt nach Max Delbrück (deutscher Biotechnologe).'),
  ('lactobacillus-bulgaricus', '⭐⭐⭐ L. delbrueckii subsp. bulgaricus (L. bulgaricus)', 'L. bulgaricus, Lactobacillus bulgaricus, subsp. bulgaricus', 'L. bulgaricus, Lactobacillus bulgaricus', 'Laktobazillus bulgaricus, Bulgarischer Bazillus', 'Joghurtkultur, Joghurtbakterium', '-', '⭐⭐⭐ JOGHURT-STARTERKULTUR! 1905 von Stamen Grigorov entdeckt. EINZIGER EU-HEALTH CLAIM für Probiotika (mit S. thermophilus)!'),
  ('lactobacillus-delbrueckii-lactis', 'L. delbrueckii subsp. lactis', 'subsp. lactis, L. lactis (FALSCH!)', 'L. delbrueckii subsp. lactis', '-', 'Käsekultur', '⚠️ NICHT verwechseln mit Lactococcus lactis!', 'Für Käseherstellung: Mozzarella, Parmesan, Emmental. Laktose-positiv.'),
  ('lactobacillus-delbrueckii-delbrueckii', 'L. delbrueckii subsp. delbrueckii', 'subsp. delbrueckii', 'L. delbrueckii subsp. delbrueckii', '-', '-', '-', 'Typsubspezies. Laktose-NEGATIV! Pflanzenhabitat.'),
  ('lactobacillus-delbrueckii-indicus', 'L. delbrueckii subsp. indicus', 'subsp. indicus', 'L. delbrueckii subsp. indicus', '-', '-', '-', 'Aus indischen Milchprodukten. Laktose-positiv. LarABCDE-Operon für Laktat-Racemisierung.'),
  ('rhodiola-rosea', 'Rhodiola rosea', 'Rosenwurz, Goldene Wurzel, Arktische Wurzel, Rosenrot', 'Rhodiola, Golden Root, Arctic Root, Roseroot, Rose Root', 'Rhodiola, Rodiola, Rhodiola rosea, R. rosea', 'Rosenwurz, das Stress-Kraut, das Wikinger-Kraut', '⚠️ Verwechslung mit anderen Rhodiola-Arten (R. crenulata, R. sachalinensis)!', '⭐ NUR R. rosea enthält Rosavine! Andere Arten: nur Salidrosid. Rosavine = Authentifizierungsmarker.'),
  ('panax-ginseng', 'Panax ginseng', 'Koreanischer Ginseng, Asiatischer Ginseng, Echter Ginseng, Roter Ginseng, Weißer Ginseng', 'Korean Ginseng, Asian Ginseng, True Ginseng, Red Ginseng, White Ginseng', 'Ginseng, P. ginseng, Panax, Gin Seng, Gin-Seng', 'Ginseng, Kraftwurzel, Allheilmittel, Menschenwurzel', '⚠️⚠️ Häufige Verwechslung mit SIBIRISCHEM "Ginseng" (Eleutherococcus)!', '⭐ Panax ginseng ≠ Sibirischer Ginseng (KEINE Ginsenoside!). ≠ Amerikanischer Ginseng (P. quinquefolius, anderes Profil).'),
  ('akazienfaser', 'Akazienfaser / Gummi Arabicum (E414)', 'Akazienfaser, Gummi arabicum, E414, Akaziengummi, Arabisches Gummi', 'Acacia fiber, Gum arabic, Acacia gum, E414, Arabic gum, Fibregum', 'Akkazienfaser, Akazien-Faser, Gummi arabikum', 'Akazie', '⚠️ Akazienfaser = Gummi arabicum = E414 → ALLES DASSELBE! Nur unterschiedliche Vermarktung.', 'Akazienfaser (Supplement-Marketing) = Gummi arabicum (Lebensmittelzusatzstoff E414). Chemisch IDENTISCH.'),
  ('lactococcus-lactis-lactis', 'L. lactis subsp. lactis', 'subsp. lactis', 'L. lactis subsp. lactis', '-', 'Käsekultur', '-', 'Typsubspezies. Arginin-Dihydrolase POSITIV. Käse-Starterkultur.'),
  ('lactococcus-lactis-cremoris', 'L. lactis subsp. cremoris', 'subsp. cremoris, Lactococcus cremoris', 'L. lactis subsp. cremoris', '-', 'Rahmkultur', '-', 'Aus Rahm/Sahne. Arginin-Dihydrolase NEGATIV. 2021 Vorschlag als eigene Art "Lactococcus cremoris".'),
  ('lactococcus-lactis-diacetylactis', 'L. lactis biovar diacetylactis', 'diacetylactis, biovar diacetylactis', 'L. lactis biovar diacetylactis', '-', 'Butterkultur, Aromakultur', '-', 'Citrat-Verwertung! Produziert DIACETYL (butterartiges Aroma) + CO₂ (Käseaugen). Wichtig für Butter, Sauerrahm.'),
  ('nisin-e234', '⭐ Nisin (E234) - aus L. lactis', 'Nisin, E234, Nisaplin, Lantibiotikum', 'Nisin, E234', '-', 'Bakteriozin, Konservierungsmittel', '-', '⭐ Klasse-I-Bakteriozin, 34 Aminosäuren (~3.350 Da). Seit 1953 kommerziell (Nisaplin). EU-zugelassen E234. ADI: 1 mg/kg KG/Tag.'),
  ('streptococcus-lactis-alt', '⚠️ Streptococcus lactis (HISTORISCH)', 'Streptococcus lactis, S. lactis', 'Streptococcus lactis (obsolete)', '-', 'Alter Name Käsekultur', '-', '⚠️ HISTORISCH! Von 1909 bis 1985 gültig. 1985 umbenannt zu LACTOCOCCUS lactis (Schleifer et al.).'),
  ('lactobacillus-amylovorus', 'Lactobacillus amylovorus', 'L. amylovorus, Lb. amylovorus', 'L. amylovorus, Lactobacillus amylovorus', 'Laktobazillus amylovorus', 'Stärke-Lactobacillus, amylolytisches Lactobacillus', '-', '⭐ 2020: BLEIBT bei LACTOBACILLUS (sensu stricto, delbrueckii-Gruppe). Typstamm ATCC 33620. EINZIGARTIG: Produziert α-AMYLASE für Stärkeabbau! Etymologie: gr. amylon (Stärke) + lat. vorare (verschlingen).'),
  ('lactobacillus-sobrius', '⚠️ Lactobacillus sobrius (SYNONYM)', 'L. sobrius', 'Lactobacillus sobrius', '-', '-', '-', '⚠️ SPÄTES SYNONYM für L. amylovorus (Konstantinov et al. 2006). Heute ungültig.'),
  ('lactobacillus-amylovorus-cp1563', '⭐⭐ L. amylovorus CP1563 (Paraprobiotikum)', 'CP1563', 'CP1563', '-', 'Paraprobiotikum, fragmentiertes Probiotikum, totes Probiotikum', '-', '⭐⭐ HAUPTSTAMM für Humanstudien! PARAPROBIOTIKUM (fragmentierte, nicht lebende Zellen). PPARα/γ-Dual-Agonist. Gewichtsmanagement-Studien mit signifikanten Ergebnissen.'),
  ('lactobacillus-amylovorus-dsm16698', 'L. amylovorus DSM 16698 (Schweine)', 'DSM 16698', 'DSM 16698', '-', 'Schweine-Probiotikum', '-', 'Schweine-Probiotikum. Hemmt ETEC K88. Aus Schweine-Ileum.'),
  ('alpha-amylase-amylovorus', '⭐ α-Amylase (L. amylovorus)', 'α-Amylase, Alpha-Amylase, Amylase', 'α-amylase, alpha-amylase', '-', 'Stärke-spaltendes Enzym', '-', '⭐ EINZIGARTIG unter Lactobacillus! Extrazelluläre α-Amylase (~140-150 kDa). Optimaler pH 5,0-6,0. Spaltet Stärke direkt zu Milchsäure ohne Vorhydrolyse.'),
  ('panax-quinquefolius', 'Amerikanischer Ginseng', 'Amerikanischer Ginseng, Xi Yang Shen, Westlicher Ginseng, Wisconsin Ginseng, Kanadischer Ginseng', 'American Ginseng, Xi Yang Shen, Western Ginseng, Wisconsin Ginseng, Canadian Ginseng, Sang', 'P. quinquefolius, Panax quinquefolium, American Ginseng, CEREBOOST', 'Der kühlende Ginseng, Yin-Ginseng', '⚠️ Häufige Verwechslung mit Koreanischem Ginseng (P. ginseng)!', '⭐ P. quinquefolius = KÜHLEND (Yin), PPD-dominant, Rb1/Rg1 >5, Marker F11. P. ginseng = WÄRMEND (Yang), PPT-dominant.'),
  ('eleutherococcus-senticosus', 'Sibirischer Ginseng (Eleuthero)', 'Sibirischer Ginseng, Eleuthero, Taigawurzel, Stachelpanax, Eleutherokokk, Teufelskralle (FALSCH!)', 'Siberian Ginseng, Eleuthero, Ci Wu Jia, Devils Shrub', 'E. senticosus, Eleutherococcus, Acanthopanax senticosus', 'Russischer Ginseng, Sowjet-Ginseng', '⚠️⚠️ KEIN ECHTER GINSENG! FDA verbietet "Ginseng"-Bezeichnung in USA!', '⭐⭐ KRITISCH: Eleuthero enthält KEINE Ginsenoside! Völlig andere Wirkstoffe (Eleutheroside). NICHT mit Panax-Arten gleichsetzen!')
INSERT INTO keywords_synonyme (supplement_id, supplement_name, synonyme_de, synonyme_en, schreibweisen, umgangssprache, verwechslungsgefahr, nicht_verwechseln_mit) VALUES
  ('arabinoxylan', 'Arabinoxylan', 'Arabinoxylan, AX, Weizen-Arabinoxylan, Pentosan, Hemicellulose', 'Arabinoxylan, AX, Wheat arabinoxylan, Pentosan, Hemicellulose', 'Arabinoxylan, Arabino-Xylan', 'MGN-3, Biobran, BRM4', '⚠️ MGN-3/Biobran = modifiziertes Reiskleie-Arabinoxylan (Markenprodukt). Nicht verwechseln mit normalem Weizen-AX.', 'Arabinoxylan (Struktur) ≠ Arabinogalactan (Akazienfaser). MGN-3/Biobran = proprietäres Produkt.'),
  ('glucomannan', 'Glucomannan (Konjak)', 'Glucomannan, Konjak, Konnyaku, E425, Konjak-Glucomannan, Teufelszunge', 'Glucomannan, Konjac, Konnyaku, E425, Konjac glucomannan, Devil''s tongue', 'Glukomanan, Glucomanan, Konjak', 'Shirataki, Konjak-Nudeln, Miracle Noodles', '⚠️ Glucomannan = Wirkstoff. Konjak = Pflanze. Shirataki = Nudelprodukt (97% Wasser).', 'E425(i) = Konjak-Gummi. E425(ii) = Konjak-Glucomannan. Beide oft zusammen als "E425" bezeichnet.'),
  ('bifidobacterium-bifidum', 'Bifidobacterium bifidum', 'B. bifidum, Bb, Bifidus, Bifidobakterium bifidum', 'B. bifidum, Bifidobacterium bifidum', 'Bifidus, Bifidum', 'Bifiduskultur, Bifidusbakterien', 'B. longum, B. infantis', '⭐ HISTORISCH: Erstes isoliertes Bifidobakterium (Tissier 1899, "Bacillus bifidus communis"). Typstamm ATCC 29521. MUKUS-SPEZIALIST mit Glykosidhydrolasen.'),
  ('bifidobacterium-bifidum-mimbbb75', '⭐⭐⭐ B. bifidum MIMBb75 (IBS)', 'MIMBb75, HI-MIMBb75', 'MIMBb75', '-', 'IBS-Probiotikum', '-', '⭐⭐⭐ BESTE IBS-EVIDENZ für B. bifidum! 47% vs 11% adequate relief (PMID: 21418261). Auch hitze-inaktiviert (HI-MIMBb75) wirksam: 34% vs 19% (PMID: 32277872).'),
  ('bifidobacterium-bifidum-bgn4', '⭐⭐ B. bifidum BGN4 (Korea)', 'BGN4', 'BGN4', '-', '-', '-', '⭐⭐ Bifido Co. Korea. Höchste Caco-2-Adhäsion, anti-allergisch, anti-inflammatorisch. FDA GRAS GRN 814.'),
  ('bifidobacterium-bifidum-g9-1', 'B. bifidum G9-1 (Japan)', 'G9-1, Biofermin', 'G9-1', '-', 'Biofermin', '-', 'Biofermin Japan. Verschreibungspflichtig für Obstipation in Japan. PMID: 33832073.'),
  ('bifidobacterium-bifidum-prl2010', 'B. bifidum PRL2010 (Forschung)', 'PRL2010', 'PRL2010', '-', '-', '-', 'Modellstamm für Mukus/HMO-Metabolismus. Vollständig sequenziert. PMID: 20974960.'),
  ('bifidobacterium-longum', 'Bifidobacterium longum', 'B. longum, Bl', 'B. longum, Bifidobacterium longum', 'Bifidus longum', '-', 'B. bifidum, B. breve', '⭐⭐⭐ WICHTIGSTE Bifidobacterium-Art! 3 Subspezies: longum, infantis, suis. Häufigste Art im Erwachsenendarm.'),
  ('bifidobacterium-longum-longum', 'B. longum subsp. longum', 'subsp. longum', 'B. longum subsp. longum', '-', '-', 'subsp. infantis', 'Typsubspezies. Hauptsächlich bei Erwachsenen. Begrenzte HMO-Verwertung (nur H5).'),
  ('bifidobacterium-longum-infantis', '⭐⭐⭐ B. longum subsp. infantis (Säuglinge!)', 'B. infantis, subsp. infantis, Bifidobacterium infantis', 'B. infantis, B. longum subsp. infantis', 'Bifidus infantis', 'Säuglings-Bifidus', 'subsp. longum', '⭐⭐⭐ SÄUGLINGS-SPEZIALIST! 43kb H1-Cluster für VOLLSTÄNDIGE HMO-Verwertung. Größtes Bifidobakterien-Genom (2,83 Mb). >90% US-Säuglinge NICHT besiedelt!'),
  ('bifidobacterium-longum-bb536', '⭐⭐⭐ B. longum BB536 (Morinaga)', 'BB536, Morinaga BB536', 'BB536', '-', 'Morinaga-Probiotikum', '-', '⭐⭐⭐ DER VETERAN! >50 Jahre, >260 Publikationen. 1969 isoliert. Japan FOSHU 1996. FDA GRAS 2009, 2019. Allergien, Immunmodulation. 2-50×10⁹ KBE.'),
  ('bifidobacterium-longum-35624', '⭐⭐⭐⭐ B. longum 35624 (Alflorex/Align)', '35624, Bifantis, B. infantis 35624', '35624, Alflorex, Align', '-', 'Alflorex, Align, IBS-Probiotikum', '-', '⭐⭐⭐⭐ IBS GOLD-STANDARD! ⚠️ Trotz "infantis" im Marketing: Genomisch B. longum subsp. longum! DOSIS-PARADOX: 1×10⁸ KBE optimal, höher NICHT besser! Alimentary Health/P&G.'),
  ('bifidobacterium-longum-evc001', '⭐⭐⭐⭐ B. infantis EVC001 (Evivo)', 'EVC001, Evivo, Infinant', 'EVC001, Evivo', '-', 'Evivo, Säuglings-Probiotikum', '-', '⭐⭐⭐⭐ SÄUGLINGS-CHAMPION! H5-positiv (vollständiges HMO-Repertoire). Evolve BioSystems/Infinant Health. >65.000 behandelte Säuglinge. 1,8×10¹⁰ KBE. KEINE EU-Autorisierung.'),
  ('bifidobacterium-longum-1714', '⭐⭐⭐ B. longum 1714 (Zenflore)', '1714, Zenflore', '1714, Zenflore', '-', 'Zenflore, Psychobiotikum, Stress-Probiotikum', '-', '⭐⭐⭐ PSYCHOBIOTIKUM! PrecisionBiotics/Alimentary Health. Cortisol ↓, Schlafqualität ↑, EEG-Veränderungen. 1×10⁹ KBE/Tag.'),
