  ('bacillus-cereus', '⚠️⚠️⚠️ Bacillus cereus - PATHOGEN!', 'B. cereus', 'B. cereus, Bacillus cereus group', 'Bacilus cereus, B cereus', '-', '⚠️⚠️⚠️ VERWECHSLUNGSGEFAHR MIT SICHEREN BACILLUS-ARTEN! Immer Toxingen-Screening!', '⚠️⚠️⚠️ LEBENSMITTELPATHOGEN! Typstamm: ATCC 14579. Eng verwandt mit B. anthracis (Milzbrand)!'),
  ('bacillus-cereus-gruppe', '⚠️⚠️⚠️ B. cereus Gruppe (sensu lato)', 'B. cereus Gruppe, B. cereus sensu lato', 'B. cereus group, B. cereus sensu lato', '-', '-', '⚠️⚠️⚠️ Umfasst auch B. ANTHRACIS (Milzbrand)!', '⚠️⚠️⚠️ PATHOGENE GRUPPE! Inkl. B. cereus, B. anthracis, B. thuringiensis, B. mycoides, B. cytotoxicus. Alle von EFSA QPS AUSGESCHLOSSEN!'),
  ('maca', 'Maca (Lepidium meyenii)', 'Maca, Maca-Wurzel, Peruanischer Ginseng, Lepidium meyenii, Lepidium peruvianum', 'Maca, Maca Root, Peruvian Ginseng, Lepidium meyenii, Lepidium peruvianum', 'Maka, Macca, Maca-Pulver, Macawurzel', 'Peruanischer Ginseng, Inka-Kraftwurzel, Anden-Ginseng', '⚠️ VERWECHSLUNGSGEFAHR: Maca ≠ Matcha (grüner Tee)! Maca ≠ Mucuna pruriens! L. meyenii ≈ L. peruvianum (Synonyme).', 'Maca = Wurzelgemüse aus Peru. KEIN echtes Ginseng (andere Pflanzenfamilie). KEIN Phytoöstrogen.'),
  ('maca-gelb', 'Gelbe Maca', 'Gelbe Maca, Yellow Maca, Standard-Maca', 'Yellow Maca, Golden Maca', 'Gelbe Maka', 'Gelbes Maca', 'Häufigste Maca-Farbe (60-70% der Ernte). Standard in den meisten Studien.', 'Gelbe Maca: Breitestes Wirkspektrum. Günstigste Variante.'),
