  ('myo-inositol-pcos', 'Myo-Inositol', 'Myo-Inositol, Inositol, MI, D-Chiro-Inositol, DCI', 'Myo-Inositol, Inositol, MI, D-Chiro-Inositol, DCI', 'inositol, myoinositol', 'Inositol', 'Myo-Inositol ≠ D-Chiro-Inositol! Verschiedene Funktionen. Optimales Verhältnis 40:1.', 'Auf 40:1-Verhältnis achten!'),
  ('folsaeure-kinderwunsch', 'Folsäure', 'Folsäure, Folat, Methylfolat, 5-MTHF, Vitamin B9', 'Folic Acid, Folate, Methylfolate, 5-MTHF, Vitamin B9', 'folsäure, folat, b9', 'Folsäure', 'Folsäure (synthetisch) muss konvertiert werden. Methylfolat (5-MTHF) ist aktive Form. Bei MTHFR: Methylfolat bevorzugen.', 'Bei MTHFR-Varianten: Methylfolat wählen.'),
  ('dhea-nicht-empfohlen', 'DHEA', 'DHEA, Dehydroepiandrosteron, Prasteron', 'DHEA, Dehydroepiandrosterone, Prasterone', 'dhea', '-', '⛔ DHEA ist ein HORMON, kein Nahrungsergänzungsmittel! In EU rezeptpflichtig.', '⛔ NICHT als NEM in EU erhältlich!'),
  ('n-acetylcystein', 'N-Acetylcystein (NAC)', 'N-Acetylcystein, NAC, Acetylcystein, N-Acetyl-L-Cystein, ACC, Fluimucil, Mucomyst', 'N-Acetylcysteine, NAC, Acetylcysteine, N-Acetyl-L-Cysteine', 'NAC, N-Acetylcystein, N Acetylcystein, Nacetylcystein, ACC', 'NAC, Hustenloeser', 'L-Cystein (NAC ist acetylierte Form), Glutathion', 'NAC ist Vorstufe von L-Cystein und damit von Glutathion; NICHT identisch mit Glutathion-Supplementen'),
  ('relora', 'Relora®', 'Relora, Magnolienrinde, Phellodendron, Honokiol, Magnolol', 'Relora, Magnolia bark, Phellodendron, Honokiol, Magnolol', 'Relora, Magnolia, Cortisol-Manager', 'Stressformel, Cortisol-Killer', '⚠️ Relora® ist Markenname - generische Magnolia/Phellodendron-Extrakte sind NICHT identisch!', 'Relora® = patentierte Kombination; generische Extrakte haben andere Standardisierung'),
  ('passionsblume', 'Passionsblume', 'Passionsblume, Passiflora, Passionflower', 'Passionflower, Passiflora incarnata, Maypop', 'Passionsblume, Passiflora, Passion-Blume', 'Beruhigungskraut, Schlafkraut', '⚠️ Passiflora incarnata ≠ Passiflora edulis (Maracuja-Frucht)', 'P. incarnata = medizinische Art; P. edulis = Frucht-Art'),
  ('folsaeure-weiblich', 'Folsäure', 'Folsäure, Folat, Vitamin B9, Pteroylglutaminsäure, Folacin', 'Folic Acid, Folate, Vitamin B9, Pteroylglutamic Acid', 'folsäure, folat, b9, vitamin b9', 'Folsäure', 'Folsäure (synthetisch) ≠ Folat (natürlich) ≠ Methylfolat (aktiv). MTHFR beeinflusst Konversion.', 'Bei MTHFR-TT: Methylfolat erwägen.'),
  ('methylfolat-5mthf', 'Methylfolat', 'Methylfolat, 5-MTHF, L-Methylfolat, 5-Methyltetrahydrofolat, Quatrefolic, Metafolin, Aktives Folat', 'Methylfolate, 5-MTHF, L-Methylfolate, Active Folate', '5-mthf, methylfolat, aktives folat', 'Methylfolat', 'Methylfolat = aktive Plasmaform. Quatrefolic® (Glucosamin-Salz) vs. Metafolin® (Calcium-Salz).', 'Markenformen beachten.'),
  ('maca-nicht-empfohlen', 'Maca', 'Maca, Lepidium meyenii, Peruanischer Ginseng, Maca-Wurzel, Andenwurzel', 'Maca, Lepidium meyenii, Peruvian Ginseng, Maca Root', 'maca, lepidium, peruanischer ginseng', '-', 'Gelbe Maca (häufigste) vs. Schwarze Maca (angeblich Spermien) vs. Rote Maca (angeblich Prostata). Evidenz für Unterschiede SCHWACH.', '⚠️ Marketing-Claims übersteigen Evidenz!'),
  ('heiliges-basilikum', 'Heiliges Basilikum (Tulsi)', 'Tulsi, Heiliges Basilikum, Indisches Basilikum, Königin der Kräuter', 'Holy Basil, Tulsi, Sacred Basil, Ocimum sanctum, Ocimum tenuiflorum', 'Tulsi, Tulsie, Tulasi, Holy Basil, Heiliges Basilicum', 'Heiliges Basilikum, Königskraut, Tempelbasilikum', '⚠️ NICHT verwechseln mit kulinarischem Basilikum (Ocimum basilicum)! Anderes Wirkstoffprofil.', 'O. tenuiflorum = Tulsi (medizinisch); O. basilicum = Küchen-Basilikum (kulinarisch)'),
  ('tribulus-fertilitaet', 'Tribulus', 'Tribulus terrestris, Erd-Burzeldorn, Erdsternchen, Tribestan', 'Tribulus terrestris, Puncture Vine, Gokhru, Gokshura, Caltrop', 'tribulus, tribestan, erd-burzeldorn', 'Testosteron-Booster (FALSCH!)', 'Tribulus ≠ Testosteron-Booster (widerlegt). Protodioscin-Gehalt variiert stark nach Herkunft!', '⚠️ Marketing für Testosteron ist wissenschaftlich NICHT belegt!'),
  ('ashwagandha-fertilitaet', 'Ashwagandha', 'Ashwagandha, Withania somnifera, Schlafbeere, Winterkirsche, Indischer Ginseng', 'Ashwagandha, Withania somnifera, Indian Ginseng, Winter Cherry', 'ashwagandha, withania, ksm-66, sensoril, schlafbeere', 'Adaptogen, Stress-Supplement', 'KSM-66® (Wurzel, 5% Withanolide) vs. Sensoril® (Wurzel+Blatt, 10% Withanolide) vs. Shoden® (35% Withanolide).', '⚠️⚠️ BfR WARNUNG Sept 2024! DK+FR verboten!'),
  ('cranberry-pacs', 'Cranberry (Proanthocyanidine)', 'Cranberry, Kranbeere, Grossfruchtige Moosbeere, Vaccinium macrocarpon, Cranberry-Extrakt, PACs', 'Cranberry, American Cranberry, Vaccinium macrocarpon, Cranberry Extract, Proanthocyanidins, PACs', 'Cranberry, Cranberries, Kranbeere, Cranberrysaft, Cranberry-Kapseln', 'Cranberry-Saft, Cranberry-Tabletten', 'Vaccinium oxycoccos (Europaeische Moosbeere - 15x weniger A-Typ-PACs!), Preiselbeere (Vaccinium vitis-idaea)', 'Vaccinium macrocarpon (Amerikanische Cranberry) hat 15x mehr A-Typ-PAC-Trimere als V. oxycoccos; Preiselbeere ist KEINE Cranberry!'),
  ('baerentraube', 'Baerentraubenblaetter', 'Baerentraube, Baerentraubenblaetter, Echte Baerentraube, Immergruene Baerentraube, Arctostaphylos uva-ursi, Uvae ursi folium, Arbutin-Droge', 'Bearberry, Bearberry Leaf, Uva Ursi, Uva-Ursi, Kinnikinnick, Mountain Cranberry, Hog Cranberry, Rockberry', 'Baerentraube, Bärentraube, Baerentraubenblätter, Uva Ursi, Uva-Ursi, Uvae ursi', 'Blasentee, Blasenkraut', 'Preiselbeere (Vaccinium vitis-idaea) - ANDERE Pflanze!, Moosbeere (Vaccinium oxycoccos)', 'Baerentraube (Arctostaphylos) ist NICHT verwandt mit Preiselbeere oder Cranberry (beides Vaccinium-Arten). Unterschiedliche Wirkstoffe: Baerentraube = Arbutin, Cranberry = PACs'),
  ('jod-schilddruese', 'Jod', 'Jod, Iod, Kaliumjodid, Kaliumiodid, Jodid', 'Iodine, Potassium Iodide, KI', 'jod, iod, jodid, schilddrüse', 'Kelp-Jod, Algen-Jod', 'Jod (Element) ≠ Jodid (Ion) ≠ Kelp (Alge mit variablem Jodgehalt). Kaliumiodid ist präzise dosierbar!', '⚠️ Kelp/Algen meiden wegen variablem Jodgehalt + Schwermetallen!'),
  ('selen-schilddruese', 'Selen', 'Selen, Selenomethionin, Natriumselenit, Selenhefe', 'Selenium, Selenomethionine, Sodium Selenite', 'selen, selenium, selenomethionin', '-', 'Selenomethionin (organisch) vs. Natriumselenit (anorganisch). Selenomethionin besser bioverfügbar.', 'Selenomethionin bevorzugen!'),
  ('vitamin-c-nebennieren', 'Vitamin C (Nebennieren)', 'Vitamin C, Ascorbinsäure, L-Ascorbinsäure, Ascorbat', 'Vitamin C, Ascorbic Acid, L-Ascorbic Acid, Ascorbate', 'VitaminC, Vit C, Vit.C, C-Vitamin', 'Vitamin C hochdosiert', '-', '-'),
  ('pantothensaeure-nebennieren', 'Pantothensäure (Nebennieren)', 'Pantothensäure, Vitamin B5, Pantothenat, Calcium-D-Pantothenat', 'Pantothenic Acid, Vitamin B5, Pantothenate, Calcium Pantothenate', 'B5, VitaminB5, Pantothensäure', 'Anti-Stress-Vitamin', '⚠️ "Anti-Stress-Vitamin" ist Marketing-Begriff ohne RCT-Evidenz!', 'Pantothensäure ≠ Pantethine (aktive Form mit Lipid-Wirkung)'),
  ('hashimoto-support', 'Hashimoto Support', 'Hashimoto, Hashimoto-Thyreoiditis, Autoimmunthyreoiditis, chronische lymphozytäre Thyreoiditis', 'Hashimoto, Hashimoto thyroiditis, autoimmune thyroiditis, chronic lymphocytic thyroiditis', 'Hashimoto, Haschimoto, Hashimodos, HT', 'Schilddrüsenentzündung, träge Schilddrüse', 'Hashimoto ≠ Hypothyreose (Hashimoto ist die URSACHE, Hypothyreose das ERGEBNIS)', 'Hashimoto kann mit Euthyreose, subklinischer oder manifester Hypothyreose einhergehen!'),
  ('graves-disease-support', 'Graves/Basedow Support', 'Morbus Basedow, Graves-Krankheit, immunogene Hyperthyreose', 'Graves disease, Basedow disease, autoimmune hyperthyroidism', 'Basedow, Graves, M. Basedow', 'Überfunktion, Schilddrüsenüberfunktion', 'Morbus Basedow ≠ Hyperthyreose (Basedow ist EINE Ursache von Hyperthyreose)', 'Basedow: TSH-Rezeptor-Antikörper (TRAb/TRAK) positiv!'),
  ('l-carnitin-graves', 'L-Carnitin (Graves)', 'L-Carnitin, Levocarnitin, Carnitin', 'L-Carnitine, Levocarnitine, Carnitine, ALCAR', 'L-Carnitin, Carnitin, Carnitine', '-', 'L-Carnitin bei Hyperthyreose ≠ L-Carnitin für Sport/Abnehmen (anderer Einsatzzweck!)', 'Bei Hyperthyreose: peripherer Hormon-Antagonist, nicht Fettverbrennung!'),
  ('myoinositol-selen-hashimoto', 'Myoinositol+Selen', 'Myoinositol, Myo-Inositol, Inositol', 'Myo-inositol, Inositol', 'Myoinositol, Inositol, Myoinsitol', '-', 'Myoinositol bei Hashimoto ≠ Myoinositol bei PCOS (anderer Wirkmechanismus!)', 'Bei Hashimoto: TSH-Signaltransduktion. Bei PCOS: Insulinsensitivität.'),
  ('urolithin-a', 'Urolithin A', 'Urolithin A, Mitopure, UA, Postbiotikum, Ellagsaeure-Metabolit, 3,8-Dihydroxy-6H-dibenzo[b,d]pyran-6-on', 'Urolithin A, Mitopure, UA, Postbiotic, Ellagic acid metabolite, Pomegranate metabolite', 'Urolithin A, urolithin a, Urolithin-A, MitoPure, mitopure, MITOPURE', 'Granatapfel-Wirkstoff, Mitochondrien-Booster, Anti-Aging-Supplement', 'Ellagsaeure (Vorstufe, nicht identisch), Urolithin B (anderer Metabolit), Granatapfelextrakt (enthaelt Ellagitannine, nicht UA)', 'Urolithin A ist NICHT Ellagsaeure oder Granatapfelextrakt - es ist der mikrobielle Metabolit, der nur von ca. 40% der Bevoelkerung produziert wird'),
  ('akkermansia-muciniphila', 'Akkermansia muciniphila (pasteurisiert)', 'Akkermansia, A. muciniphila, Akkermansia muciniphila, pasteurisierte Akkermansia, MucT, Next-Generation Probiotikum', 'Akkermansia, A. muciniphila, Akkermansia muciniphila, pasteurized Akkermansia, MucT, Next-Generation Probiotic', 'Akkermansia, akkermansia, Akermansia, Ackermansia, A. muciniphila, Akkermansia mucinifila', 'Darm-Schleim-Bakterium, Abnehm-Bakterium, Stoffwechsel-Probiotikum', 'Klassische Probiotika (Lactobacillus, Bifidobacterium - andere Gattungen), Lebende Akkermansia (NICHT in EU zugelassen)', 'NUR pasteurisierte Form in EU zugelassen; lebende Form ist NICHT dasselbe Produkt und hat andere Wirkprofile; Pendulum-Produkte (USA) enthalten lebende Form'),
  ('honokiol', 'Honokiol (isoliert)', 'Honokiol, HNK, 2-(4-Hydroxy-3-prop-2-en-1-ylphenyl)-4-prop-2-en-1-ylphenol, Biphenyl-Neolignan, Magnolia-Wirkstoff', 'Honokiol, HNK, Biphenyl Neolignan, Magnolia Active Compound', 'Honokiol, honokiol, Honokioll, HNK', 'Magnolien-Wirkstoff, Angst-Rinde', 'Magnolol (Strukturisomer!), Magnolienrinde (Gesamtextrakt), Relora (Kombipraeparat mit Phellodendron)', 'Honokiol ist EIN EINZELNER Wirkstoff aus Magnolienrinde. Magnolol ist das Strukturisomer (gleiche Formel C18H18O2, andere Bindungsposition). Relora enthaelt nur ~1,5% Honokiol. Isoliertes Honokiol ≠ Magnolienrinden-Extrakt!'),
  ('palmitoylethanolamid', 'Palmitoylethanolamid (PEA)', 'Palmitoylethanolamid, PEA, N-Palmitoylethanolamin, Impulsin, Normast, ALIAmid, Fettsaeureamid', 'Palmitoylethanolamide, PEA, N-Palmitoylethanolamide, Impulsin, Normast, ALIAmide', 'PEA, pea, Palmitoylethanolamin, Palmitoyl-Ethanolamid, Palmitoyl Ethanolamid', 'PEA, Schmerzmittel natuerlich, natuerliches Schmerzmittel', 'CBD/Cannabidiol, Anandamid, Endocannabinoide', 'PEA ist KEIN Endocannabinoid und KEIN Cannabis-Derivat. Keine CB1/CB2-Bindung. Gehoert zu N-Acylethanolamiden.'),
  ('cistus-incanus', 'Zistrose (Cistus incanus)', 'Zistrose, Cistus, Cystus, Cistuskraut, Graubehaarte Zistrose, Kretische Zistrose', 'Cistus, Rock Rose, Pink Rock Rose, Cistus incanus, Cistus creticus', 'Zistrose, Cistrose, Cystus, cistus, zistrose, Cistus incanus', 'Cystus-Tee, Cistus-Tee, Zistrosentee, Grippekraut', 'Cistus ladanifer (andere Art!), Labdanum (Harzprodukt)', 'C. incanus/creticus ist die klinisch untersuchte Art. C. ladanifer hat hoechste Antioxidanskapazitaet, ist aber NICHT die in Studien verwendete Art.'),
  ('rapamycin', 'Rapamycin', 'Rapamycin, Sirolimus, Rapamune, mTOR-Inhibitor, mTOR-Hemmer, RAPA, AY-22989', 'Rapamycin, Sirolimus, Rapamune, mTOR inhibitor', 'Rapamicin, Rapamyzin, Sirolimus, Rapamune', 'Anti-Aging-Pille, Langlebigkeits-Medikament', 'Everolimus (Afinitor/Certican), Temsirolimus (Torisel), Ridaforolimus', 'Everolimus ist ein Derivat mit besserer Bioverfuegbarkeit; Temsirolimus ist ein Prodrug von Sirolimus. NICHT identisch!'),
  ('ipamorelin', 'Ipamorelin', 'Ipamorelin, NNC 26-0161, Ipamorelin-Acetat, GHS-R1a-Agonist', 'Ipamorelin, NNC 26-0161, growth hormone secretagogue', 'Ipamorelin, Ipamorilin, Ipamorellin', 'Wachstumspeptid, GH-Peptid, Anti-Aging-Peptid', 'GHRP-6, GHRP-2, Hexarelin, MK-677 (Ibutamoren), CJC-1295', 'GHRP-6/GHRP-2 sind NICHT selektiv (erhoehen auch Cortisol/Prolaktin). MK-677 ist oral, nicht peptidisch. CJC-1295 wirkt am GHRH-Rezeptor, nicht GHS-R1a.'),
  ('sermorelin', 'Sermorelin', 'Sermorelin, Sermorelin-Acetat, Geref, GRF(1-29)NH2, GHRH(1-29), Somatorelin(1-29)', 'Sermorelin, Sermorelin acetate, Geref, GHRH(1-29)', 'Sermorelin, Semorelin, Sermoreline', 'GH-Releasing-Hormon-Peptid, Anti-Aging-Peptid', 'CJC-1295, CJC-1293, Tesamorelin, GHRH (1-44)', 'Tesamorelin (Egrifta) ist ein GHRH-Analogon mit FDA-Zulassung (HIV-Lipodystrophie). CJC-1295 hat laengere HWZ durch DAC-Konjugation. GHRH(1-44) ist das vollstaendige endogene Hormon.'),
  ('bpc-157', 'BPC-157', 'BPC-157, BPC 157, PL 14736, Bepecin, Body Protection Compound 157, Stabiles Magenspeptid', 'BPC-157, BPC 157, Body Protection Compound 157, PL 14736', 'BPC157, BPC-157, BPC 157, Bepecin', 'Heilungspeptid, Regenerationspeptid, Magenspeptid', 'TB-500/Thymosin Beta-4 (anderer Mechanismus), Kollagen-Peptide (zugelassen, evidenzbasiert)', 'TB-500 wirkt ueber Aktin-Bindung, BPC-157 ueber VEGFR2. Kollagen-Peptide sind ZUGELASSENE Nahrungsergaenzungsmittel mit Evidenz - BPC-157 NICHT.'),
  ('tb-500', 'TB-500', 'TB-500, Thymosin Beta-4, Tbeta4, Tb4, Timbetasin, Ac-LKKTETQ', 'TB-500, Thymosin Beta-4, Tβ4, Timbetasin', 'TB500, TB-500, Thymosin beta 4, Thymosin b4', 'Heilungspeptid, Regenerationspeptid, Pferdepeptid', 'BPC-157 (anderer Mechanismus), Thymalin (Thymus-Extrakt, NICHT identisch), Thymosin Alpha-1 (Zadaxin, anderes Protein)', 'TB-500 (7 AA Fragment) ≠ Thymosin Beta-4 (43 AA vollstaendiges Protein)! Viele Anbieter verkaufen Tbeta4 als TB-500. Thymosin Alpha-1 (Zadaxin) ist ein ANDERES Thymus-Protein mit Immunfunktion.'),
  ('agarikon', 'Agarikon (Lärchenschwamm)', 'Lärchenschwamm, Apothekerschwamm, Agaricum, Eburiko', 'Agarikon, Quinine Conk, Bread of Ghosts, Larch Polypore', 'Agaricon, Agaricum, Laricifomes, Fomitopsis officinalis', 'Lärchenpilz, Apothekerpilz', 'Agaricus blazei (= Mandelpilz — KOMPLETT anderer Pilz!); Agaricus bisporus (= Champignon); Fomitopsis betulina (= Birkenporling, Ötzi-Pilz); Dr. Myko San AGARIKON.1 (= Multi-Pilz-Blend, NICHT reines Agarikon!)', '⚠️ Agarikon (Laricifomes officinalis) ist ein PORLING auf Lärchen — NICHT verwechseln mit: Agaricus blazei (ABM/Mandelpilz = Blätterpilz!), Agaricus bisporus (Champignon). Ötzi trug NICHT Agarikon sondern Fomitopsis betulina (Birkenporling) und Fomes fomentarius (Zunderschwamm). AGARIKON.1 von Myko San enthält 6 verschiedene Pilze, NICHT reines Agarikon.'),
  ('liposomales-zink', 'Liposomales Zink', 'Lipo-Zink, Liposomales Zink, Zink-Liposom, Nano-Zink', 'Liposomal Zinc, Lipo Zinc, Nano Zinc, Zinc Liposome', 'Liposomales Zink, liposomales Zinc, Lipo Zinc, LipoZink', 'Zink in Fettkügelchen, Fett-Zink', 'Zinkbisglycinat (= Chelat, KEIN Liposom); Zinkpicolinat (= organisches Salz); Zinkcitrat; Zinksulfat; Zinkgluconat. JEDES ''liposomale'' Produkt kann andere Zinkform enthalten!', 'Liposomales Zink ist KEINE spezifische Zinkverbindung — es ist eine DELIVERY-Form. Die Zinkform INNERHALB der Liposomen variiert (Ascorbat, Bisglycinat, Citrat, Sulfat, Oxid). Viele ''liposomale'' Produkte enthalten KEINE echten Liposomen (ASA UK 2021 vs. YourZooki).'),
  ('liposomales-eisen', 'Liposomales Eisen / Sucrosomiales Eisen', 'Sucrosomiales Eisen, Sideral, Sideral Forte, Sideral RM, Lipofer, SunActive Fe, Eisen-Liposom', 'Sucrosomial Iron, Liposomal Iron, Sideral, Lipofer, SunActive Fe', 'Sucrosomiales Eisen, Sideral, liposomales Eisen, Lipo-Eisen, Sucrosomal Iron', 'Magenfreundliches Eisen, verträgliches Eisen', 'Standard-Eisensulfat (= KEIN Liposom); Eisenbisglycinat (= Chelat); Eisenfumarat; IV-Eisen (Ferinject, Venofer); Lipofer® (= einfaches Phospholipid, NICHT Sucrosome®); SunActive® (= mikronisiert, KEIN Liposom)', 'Sucrosomiales Eisen (Sideral®) ist NICHT identisch mit generischem ''liposomalem Eisen''! Sideral® = Fe³⁺-Pyrophosphat in patentierter Sucrosome®-Matrix (Phospholipid + Sucrester + Tricalciumphosphat + Stärke). Lipofer® = nur Phospholipid-Hülle (weniger wirksam in Caco-2). SunActive® = mikronisiert (kein Liposom).'),
  ('liposomales-coq10', 'Liposomales Coenzym Q10', 'Liposomales CoQ10, Lipo-CoQ10, Liposomales Ubichinon, Liposomales Q10', 'Liposomal CoQ10, Liposomal Ubiquinone, LipoVantage CoQ10', 'Liposomales CoQ10, liposomales Q10, Lipo CoQ10, LipoQ10', 'CoQ10 in Fettkügelchen', 'Kristalldispergiertes CoQ10 (Myoqinon/Bio-Qinon = Q-SYMBIO-Form); Ubiquinol (Kaneka QH = reduzierte Form); Q-Sorb (= solubilisiert); Q10Vital® (= wasserlöslich); Nanoemulsion CoQ10', 'Liposomales CoQ10 ≠ Ubiquinol! Ubichinon (oxidiert) = meist eingekapselt. Ubiquinol (Kaneka QH) = reduziert, eigene Formulierung, 85+ Studien. Kristalldispergiertes Ubichinon (Pharma Nord) hat BESTE Evidenz (Q-SYMBIO). Liposomal zeigt nur +22-31% Verbesserung (1 firmengesponserte Studie) vs. 4-6× für kristalldispergiert.'),
  ('pentadecansaeure-c15', 'Pentadecansaeure (C15:0)', 'Pentadecansaeure, Pentadecylsaeure, C15:0, FA15, Ungeradzahlige Fettsaeure', 'Pentadecanoic acid, C15:0, Odd-chain fatty acid, OCFA, FA15', 'C15, C15:0, Pentadecansaeure, Pentadecanoic, fatty15, Fatty 15, pentadecansaure', 'Die essentielle Fettsaeure, Milchfettsaeure', 'C17:0 (Heptadecansaeure/Margarinsaeure - andere OCFA), C16:0 (Palmitinsaeure - geradzahlig!)', 'C15:0 und C17:0 sind beide ungeradzahlige Fettsaeuren, aber C15:0 scheint die aktivere zu sein (Bishop 2023). C16:0 (Palmitinsaeure) ist NICHT verwandt und hat negative Gesundheitsassoziationen.'),
  ('paraxanthin', 'Paraxanthin', 'Paraxanthin, 1,7-Dimethylxanthin, p-Xanthin, enfinity', 'Paraxanthine, 1,7-Dimethylxanthine, p-Xanthine, enfinity', 'Paraxanthin, paraxanthine, Paraxantin, enfinity, 1,7-DMX, 17-dimethylxanthin', 'Sauberes Koffein, Clean Caffeine, Next-Gen Caffeine', 'Koffein (1,3,7-Trimethylxanthin - Muttersubstanz), Theobromin (3,7-DMX - in Kakao), Theophyllin (1,3-DMX - Asthma-Medikament)', 'Paraxanthin ist METABOLIT von Koffein (nicht Koffein selbst). Theobromin und Theophyllin sind andere Koffein-Metaboliten. Alle vier sind Xanthin-Derivate aber mit unterschiedlichen Wirkprofilen.'),
  ('ghk-cu', 'GHK-Cu (Kupferpeptid)', 'GHK-Cu, Kupferpeptid, Kupfertripeptid-1, Glycyl-L-Histidyl-L-Lysin-Kupfer(II), Copper Tripeptide-1, GHK Kupfer, Kupfer-Tripeptid', 'GHK-Cu, Copper Peptide, Copper Tripeptide-1, Glycyl-L-Histidyl-L-Lysine Copper(II), GHK Copper', 'GHK-Cu, ghk cu, GHK Cu, GHKCu, Kupferpeptid, kupferpeptid, Copper Peptide, copper peptide, GHK-Kupfer', 'Kupferpeptid, Kupferserum, Anti-Aging-Peptid, Wundpeptid', 'Kupfergluconat (nur Kupferquelle, kein Peptid), Kupferbisglycinat (nur Kupferquelle), AHK-Cu (anderes Analogon), BPC-157 (anderes Peptid)', 'GHK-Cu ist ein bioaktives Signalmolekuel (Tripeptid+Kupfer), NICHT vergleichbar mit einfachen Kupfersupplements. Orale Kupfersupplements (Kupfergluconat) liefern nur Kupfer ohne Peptid-Signalwirkung. AHK-Cu ist ein weniger erforschtes Analogon.'),
  ('ahcc', 'AHCC (Active Hexose Correlated Compound)', 'AHCC, Active Hexose Correlated Compound, Alpha-Glucan-Extrakt, Shiitake-Myzelextrakt, Basidiomyceten-Myzelextrakt', 'AHCC, Active Hexose Correlated Compound, Alpha-Glucan Extract, Shiitake Mycelium Extract', 'AHCC, ahcc, Ahcc, alpha-glucan, Alpha Glucan, Active hexose, active hexose correlated compound', 'Shiitake-Extrakt (ungenau!), Pilzextrakt, Immunpilz', 'Lentinan (beta-Glucan aus Shiitake-FRUCHTKOERPER, IV-Arzneimittel), Shiitake-Speisepilz (Fruchtkoerper, NICHT Myzel), Beta-Glucan-Extrakte (andere Pilzart/Glucan-Typ)', 'AHCC stammt aus Shiitake-MYZEL (nicht Fruchtkoerper) und enthaelt primaer ALPHA-1,4-Glucane (~20%), NICHT Beta-Glucane (~2%). Lentinan ist ein voellig anderes Produkt (beta-1,3-Glucan, MW 500.000 Da, nur IV). Generische alpha-Glucan-Extrakte sind NICHT klinisch getestet wie AHCC.'),
  ('faecalibacterium-prausnitzii', 'Faecalibacterium prausnitzii', 'F. prausnitzii, Faecalibacterium, Butyrat-Produzent, EXL01, Butyratbildner, Darmschluessel-Bakterium', 'F. prausnitzii, Faecalibacterium, butyrate producer, EXL01, gut keystone bacterium', 'F. prausnitzii, Faecalibacterium prausnitzii, F prausnitzii, Faecalbacterium, Fecalibacterium, faecalibacterium', 'Butyrat-Bakterium, Entzuendungshemmer im Darm, Crohn-Bakterium', 'F. duncaniae (ehemals Stamm A2-165), Roseburia intestinalis (anderer Butyrat-Produzent), Clostridium-Cluster IV (Uebergruppe)', 'Stamm A2-165 gehoert seit 2022 zu F. duncaniae (NICHT mehr F. prausnitzii sensu stricto). Roseburia ist ein anderer Butyrat-Produzent. Faecalibacterium umfasst mittlerweile 7+ Spezies.'),
  ('christensenella-minuta', 'Christensenella minuta', 'C. minuta, Christensenella, Schlank-Bakterium, Xla1, Duenn-Bakterium, Christensenellaceae', 'C. minuta, Christensenella, slim bacterium, lean bacterium, heritable gut bacterium, Xla1', 'Christensenella minuta, C. minuta, C minuta, Christensenella, christensenella, Christensenellaceae', 'Schlank-Bakterium, Duenn-Bakterium, Abnehm-Bakterium, Genetisches Darmbakterium', 'Christensenella timonensis (andere Art), Christensenella massiliensis (andere Art), Akkermansia muciniphila (anderes NGP)', 'C. minuta ist die bekannteste Art der Familie Christensenellaceae. Nicht verwechseln mit C. timonensis oder C. massiliensis (andere Arten). Akkermansia muciniphila ist ein anderes NGP mit EU-Zulassung (pasteurisiert).'),
  ('baicalein', 'Baicalein', 'Baicalein, 5,6,7-Trihydroxyflavon, Noroxylin, Baikalein', 'Baicalein, 5,6,7-Trihydroxyflavone, Noroxylin', 'Baicalein, Baikalein, Baicalin (Verwechslung!), Baikal-Helmkraut', 'Helmkraut-Wirkstoff, Scutellaria-Aglykon', 'Baicalin (das Glykosid, NICHT das Aglykon), Scutellaria lateriflora (andere Art!)', 'Baicalein = Aglykon (zuckerfrei, aktiver, lipophiler, 270 g/mol). Baicalin = Glykosid (mit Glucuronsaeure, 446 g/mol). Scutellaria baicalensis (Baikal-Helmkraut) ≠ Scutellaria lateriflora (Amerikanisches Helmkraut).'),
  ('gastrodin', 'Gastrodin', 'Gastrodin, Gastrodine, Tianma, Gastrodia-Extrakt', 'Gastrodin, Gastrodine, Tianma extract', 'Gastrodin, Gastrodine, Tian Ma, Tianma, Gastrodia', 'Tianma-Wirkstoff, Orchideen-Extrakt', 'Gastrodia elata (die Pflanze) vs. Gastrodin (der isolierte Wirkstoff), p-Hydroxybenzylalkohol (HBA, der aktive Metabolit)', 'Gastrodin = Glykosid aus Gastrodia elata. Wird zu HBA (p-Hydroxybenzylalkohol) metabolisiert. HBA ist moeglicherweise der eigentliche Wirkstoff. Gastrodia elata = Tianma (TCM-Name).'),
  ('lentinan', 'Lentinan', 'Lentinan, Shiitake-beta-Glucan, Lentinula-edodes-Polysaccharid', 'Lentinan, Shiitake beta-glucan, Lentinula edodes polysaccharide', 'Lentinan, Shiitake Glucan, Lentinex', 'Shiitake-Wirkstoff, Pilz-Polysaccharid', 'AHCC (alpha-Glucan aus Shiitake-MYZEL, 5 kDa - NICHT identisch!), Generischer Shiitake-Extrakt (Mischung diverser Bioaktiva - NICHT identisch!)', 'Lentinan = gereinigtes beta-(1->3)-Glucan (~500 kDa, Tripelhelix) aus Shiitake-FRUCHTKOERPER. AHCC = alpha-Glucan (~5 kDa) aus Shiitake-MYZEL. Shiitake-Extrakt = ungereinigtes Gemisch. Drei verschiedene Produkte mit unterschiedlicher Evidenz!'),
  ('psk-krestin', 'PSK / Krestin', 'PSK, Krestin, Polysaccharid-K, Polysaccharid-Kureha, Coriolus-Polysaccharid', 'PSK, Krestin, Polysaccharide-K, Coriolus versicolor polysaccharide, Turkey Tail extract', 'PSK, Krestin, Crestine, PS-K, Polysaccharid K, Coriolus, Turkey Tail', 'Truthahnschwanz-Wirkstoff, Schmetterlingstramete', 'PSP (Polysaccharopeptid, chinesisch, COV-1-Stamm - NICHT identisch!), Generische Turkey-Tail/Coriolus-Extrakte (NICHT aequivalent!), Trametes versicolor Fruchtkörper-Extrakt', 'PSK = spezifisches pharmazeutisches Produkt von Kureha Corp., Stamm CM-101 (japanisch). PSP = anderes Produkt, Stamm COV-1 (chinesisch). Generische Coriolus-Extrakte tragen NICHT die PSK-Evidenz! Turkey Tail Mushroom Supplements ≠ PSK.'),
  ('roseburia-intestinalis', 'Roseburia intestinalis', 'Roseburia intestinalis, Roseburia, R. intestinalis, Cluster XIVa Butyrat-Produzent', 'Roseburia intestinalis, Roseburia, R. intestinalis, Cluster XIVa butyrate producer, Lachnospiraceae', 'Roseburia, roseburia intestinalis, R. intestinalis, R intestinalis', 'Butyrat-Bakterium, Darmflora-Bakterium', 'Roseburia hominis, Roseburia inulinivorans, Roseburia faecis, Faecalibacterium prausnitzii', 'R. intestinalis ist eine von mind. 5 Roseburia-Arten. NICHT verwechseln mit F. prausnitzii (anderer Butyrat-Produzent, andere Familie). R. hominis ist eine separate Spezies.'),
  ('anaerobutyricum-hallii', 'Anaerobutyricum hallii / soehngenii', 'Anaerobutyricum hallii, Anaerobutyricum soehngenii, Eubacterium hallii, A. hallii, A. soehngenii, CH-106', 'Anaerobutyricum hallii, Anaerobutyricum soehngenii, Eubacterium hallii, A. hallii, A. soehngenii, CH-106, Caelus Health', 'Eubacterium hallii, E. hallii, Anaerobutyricum, anaerobutyricum hallii, A hallii, A soehngenii', 'Laktat-Recycler, Darmflora-Bakterium', 'Anaerostipes hadrus, Clostridium butyricum, Eubacterium rectale', 'A. hallii und A. soehngenii sind VERSCHIEDENE Arten (nur 26,25% DNA-DNA-Hybridisierung)! Alle klinischen Studien verwenden A. soehngenii (CH-106). Nicht verwechseln mit Anaerostipes hadrus (nutzt nur D-Laktat).'),
  ('withaferin-a', 'Withaferin A', 'Withaferin A, WA, Withaferin, Withanolid, Ashwagandha-Withanolid, steroidales Lacton', 'Withaferin A, WA, Withanolide, Ashwagandha withanolide, steroidal lactone', 'Withaferin, Withaferin-A, Withaferin A, withaferin a', 'Ashwagandha-Wirkstoff, Schlafbeere-Wirkstoff', 'Withanolid A, Withanoside IV, Ashwagandha-Gesamtextrakt (KSM-66, Sensoril)', 'Withanolid A ist neuroprotektiv (BDNF); Withaferin A ist zytotoxisch. KSM-66 enthaelt <0,1% WA und hat voellig andere Wirkung als isoliertes WA!'),
  ('magnolol', 'Magnolol', 'Magnolol, Magnolia-Neolignan, Houpo-Wirkstoff, biphenolisches Neolignan', 'Magnolol, Magnolia neolignan, biphenolic neolignan', 'Magnolol, magnolol, Magnoiol', 'Magnolienrinden-Wirkstoff', 'Honokiol (Regioisomer), Magnolienrinde, Relora', 'Magnolol hat ortho-ortho OH-Gruppen, Honokiol ortho-para. Magnolol ist CB2-Agonist, Honokiol CB1-Agonist/CB2-Antagonist - gegensaetzliche Cannabinoid-Profile!'),
  ('nrh', 'Dihydronicotinamid-Ribosid (NRH)', 'NRH, Dihydronicotinamid-Ribosid, Reduziertes Nicotinamid-Ribosid, Reduziertes NR, 1,4-Dihydro-NR', 'NRH, Dihydronicotinamide Riboside, Reduced Nicotinamide Riboside, Reduced NR, 1,4-Dihydro-NR', 'NRH, nrh, Dihydronicotinamidribosid, Di-hydro-NR', 'Reduziertes NR, Super-NR, Starkes NAD-Vitamin', 'NR (Nicotinamid-Ribosid), NMN (Nicotinamid-Mononukleotid), NADH', 'NRH ist die REDUZIERTE Form von NR (1,4-Dihydropyridin statt Pyridinium); NMN hat eine Phosphatgruppe; NADH ist das Endprodukt, nicht der Vorlaeufer. NRH ist NICHT zugelassen!'),
  ('skq1', 'SkQ1 / Visomitin', 'SkQ1, Visomitin, Skulachev-Ion, Plastoquinonyl-decyl-triphenylphosphonium, Plastomitin', 'SkQ1, Visomitin, Skulachev Ion, Plastoquinonyldecyltriphenylphosphonium, Plastomitin', 'SkQ1, SKQ1, skq1, Visomitin, plastomitin', 'Skulachev-Tropfen, Russische Augentropfen, Mitochondrien-Tropfen', 'MitoQ, CoQ10, Idebenon, SS-31 (Elamipretide)', 'SkQ1 nutzt Plastochinon (MitoQ nutzt Ubichinon); SkQ1 ist Arzneimittel (Augentropfen in RU), KEIN Supplement; MitoQ ist als Supplement erhaeltlich'),
  ('plasmalogene', 'Plasmalogene', 'Plasmalogene, Ethanolamin-Plasmalogen, Cholin-Plasmalogen, PlsEtn, PlsCho, Plasmenylethanolamin, Vinyl-Ether-Phospholipide', 'Plasmalogens, Ethanolamine Plasmalogen, Choline Plasmalogen, PlsEtn, PlsCho, Vinyl-Ether Phospholipids', 'Plasmalogen, Plasmalogens, Plasmalogene, PlsEtn, PlsCho', 'Gehirn-Fette, Gehirn-Lipide, Nervenfette', 'Phosphatidylcholin, Phosphatidylserin, Sphingomyelin, Lecithin', 'Plasmalogene = Vinyl-ETHER-Bindung; PC/PS = ESTER-Bindung. Lecithin ≠ Plasmalogen.'),
  ('piperlongumin', 'Piperlongumin', 'Piperlongumin, Piplartine, Langer-Pfeffer-Extrakt, Pippali-Extrakt', 'Piperlongumine, Piplartine, Long Pepper Extract, Pippali Extract', 'Piperlongumine, Piperlongumin, Piplartine, PL, Pippali', 'Langer-Pfeffer-Senolytikum', 'Piperin (schwarzer Pfeffer!), Piper nigrum', 'Piperlongumin = Piper LONGUM (Langer Pfeffer). Piperin = Piper NIGRUM (schwarzer Pfeffer). NICHT verwechseln! Piperin hat KEINE senolytische Wirkung.')
